-- Migration 002: Seed questions for full ACT test mode
-- Inserts 215+ questions: 75 English, 60 Math, 40 Reading, 40 Science
-- Distributed across skill tags and difficulty levels (easy/medium/hard)
-- Requirements: 2.7, 2.8
--
-- NOTE: This migration is additive - it does not modify or delete existing data.
-- The questions use skill_tags from the SKILL_TAGS constant in question.service.ts:
--   English: punctuation, grammar_usage, sentence_structure, style, organization,
--            word_choice, verb_tense, pronoun_agreement, modifier_placement, parallelism
--   Math: pre_algebra, elementary_algebra, intermediate_algebra, coordinate_geometry,
--         plane_geometry, trigonometry, number_properties, ratios_proportions, functions, statistics_probability
--   Reading: main_idea, detail_identification, inference, vocabulary_in_context, author_purpose,
--            tone_attitude, cause_effect, comparison_contrast, sequence_events, generalization
--   Science: data_representation, research_summaries, conflicting_viewpoints, interpreting_graphs,
--            experimental_design, variable_relationships, hypothesis_evaluation, data_trends,
--            scientific_reasoning, units_measurements

-- ═══════════════════════════════════════════════════════════════════════════════
-- ENGLISH QUESTIONS (75 total)
-- ═══════════════════════════════════════════════════════════════════════════════

INSERT INTO questions (question_id, section, question_text, passage, options, correct_answer, explanation, incorrect_reasoning, skill_tag, difficulty, strategy_tip) VALUES
-- punctuation (8 questions: 3 easy, 3 medium, 2 hard)
('a0000000-0001-0000-0000-000000000001','english','Which sentence uses commas correctly?',NULL,'["A) The dog, ran quickly, to the park.","B) The dog ran quickly to the park.","C) The, dog ran quickly to the park.","D) The dog ran, quickly to, the park."]','B','No commas are needed in this simple sentence.','{"A":"Separates subject from verb","C":"Comma after article","D":"Breaks up predicate"}','punctuation','easy','Only add commas when grammar requires: lists, introductory phrases, or nonessential clauses.'),
('a0000000-0001-0000-0000-000000000002','english','Which sentence correctly punctuates a list?',NULL,'["A) I bought eggs milk and bread.","B) I bought eggs, milk, and bread.","C) I bought, eggs milk and bread.","D) I bought eggs milk, and bread."]','B','Commas separate items in a series. The Oxford comma before and is standard.','{"A":"Missing all commas","C":"Comma after verb is wrong","D":"Missing first comma"}','punctuation','easy','Use commas between three or more items in a series.'),
('a0000000-0001-0000-0000-000000000003','english','Which uses an apostrophe correctly?',NULL,'["A) The dogs'' toys are scattered.","B) The dog''s are playing.","C) Its a nice day.","D) The dogs toy is here."]','A','Dogs'' shows possession by multiple dogs (plural possessive).','{"B":"Apostrophe making a plural is wrong","C":"Should be it''s for it is","D":"Missing possessive apostrophe"}','punctuation','easy','Plural possessive: add apostrophe after the s (dogs'').'),
('a0000000-0001-0000-0000-000000000004','english','Which sentence correctly uses a colon?',NULL,'["A) She bought: apples and oranges.","B) She needed three things: apples, oranges, and milk.","C) She: bought three items.","D) She bought items apples: and oranges."]','B','A colon follows a complete independent clause and introduces a list.','{"A":"Clause before colon is not independent","C":"Colon after subject is wrong","D":"Colon placed mid-list"}','punctuation','medium','A colon must follow a complete sentence.'),
('a0000000-0001-0000-0000-000000000005','english','Which sentence correctly punctuates a nonrestrictive clause?',NULL,'["A) My brother who lives in Texas is visiting.","B) My brother, who lives in Texas, is visiting.","C) My brother who lives in Texas, is visiting.","D) My, brother who lives in Texas is visiting."]','B','Nonrestrictive clauses add extra info and need commas on both sides.','{"A":"Missing commas for nonessential clause","C":"Missing opening comma","D":"Comma in wrong place"}','punctuation','medium','If the clause adds extra detail (can be removed), use commas.'),
('a0000000-0001-0000-0000-000000000006','english','Which uses a semicolon and conjunctive adverb correctly?',NULL,'["A) The road was icy, therefore, we drove slowly.","B) The road was icy; therefore, we drove slowly.","C) The road was icy therefore we drove slowly.","D) The road was icy therefore; we drove slowly."]','B','Semicolon before conjunctive adverb, comma after.','{"A":"Comma splice","C":"Run-on sentence","D":"Semicolon misplaced"}','punctuation','medium','Pattern: clause; however/therefore/moreover, clause.'),
('a0000000-0001-0000-0000-000000000007','english','Which sentence correctly uses dashes?',NULL,'["A) The results—which surprised everyone—were published Friday.","B) The results—which surprised everyone were published Friday.","C) The results which surprised—everyone were published Friday.","D) The—results which surprised everyone were published Friday."]','A','Dashes set off a nonessential parenthetical and must come in pairs mid-sentence.','{"B":"Missing closing dash","C":"Dash in wrong position","D":"Dash splits the subject"}','punctuation','hard','Dashes come in pairs for mid-sentence interruptions, like parentheses.'),
('a0000000-0001-0000-0000-000000000008','english','Which sentence correctly uses a hyphen in a compound modifier?',NULL,'["A) She is a well known author.","B) She is a well-known author.","C) She is a well known-author.","D) She is a-well known author."]','B','Compound modifiers before a noun are hyphenated: well-known author.','{"A":"Missing hyphen in compound modifier","C":"Hyphen connects wrong words","D":"Hyphen in wrong position"}','punctuation','hard','Hyphenate compound adjectives that come before a noun: well-known, fast-paced.'),
-- grammar_usage (8 questions: 3 easy, 3 medium, 2 hard)
('a0000000-0002-0000-0000-000000000001','english','Select the sentence with correct subject-verb agreement.',NULL,'["A) The group of students are ready.","B) The group of students is ready.","C) The group of students were ready.","D) The group of students have been ready."]','B','Group is a singular collective noun requiring singular verb is.','{"A":"Plural verb with singular subject","C":"Plural past verb","D":"Plural auxiliary"}','grammar_usage','easy','Ignore prepositional phrases between subject and verb.'),
('a0000000-0002-0000-0000-000000000002','english','Which uses the correct pronoun case?',NULL,'["A) Me and him went to the store.","B) He and I went to the store.","C) Him and I went to the store.","D) Me and he went to the store."]','B','Subject pronouns (He, I) are used as subjects of verbs.','{"A":"Object pronouns as subjects","C":"Mixed cases","D":"Mixed cases"}','grammar_usage','easy','Use subject pronouns (I, he, she, they) as subjects. Test by removing the other person.'),
('a0000000-0002-0000-0000-000000000003','english','Which correlative conjunction pair is correct?',NULL,'["A) Neither the cat or the dog was fed.","B) Neither the cat nor the dog was fed.","C) Either the cat nor the dog was fed.","D) Both the cat nor the dog was fed."]','B','Neither pairs with nor. Either pairs with or. Both pairs with and.','{"A":"Neither pairs with nor not or","C":"Either pairs with or not nor","D":"Both pairs with and not nor"}','grammar_usage','easy','Memorize: either/or, neither/nor, both/and, not only/but also.'),
('a0000000-0002-0000-0000-000000000004','english','Which correctly uses fewer vs. less?',NULL,'["A) There are less students today.","B) There are fewer students today.","C) There is fewer water.","D) There is less students."]','B','Fewer for countable nouns (students). Less for uncountable nouns (water).','{"A":"Less for uncountable nouns only","C":"Fewer for countable only; water is uncountable","D":"Less for uncountable; subject-verb disagreement"}','grammar_usage','medium','Fewer = countable (fewer books). Less = uncountable (less water).'),
('a0000000-0002-0000-0000-000000000005','english','Which correctly uses who vs. whom?',NULL,'["A) Who did you give the book to?","B) Whom did you give the book to?","C) Whom is coming to dinner?","D) Who are you?"]','B','Whom is the object of to. Test: you gave it to him (object).','{"A":"Who is subject form used as object","C":"Whom used as subject—should be who","D":"Correct but tests subject use, not the target skill"}','grammar_usage','medium','Substitute he/him: if him fits use whom. If he fits use who.'),
('a0000000-0002-0000-0000-000000000006','english','Which sentence correctly uses the comparative form?',NULL,'["A) She is more taller than her sister.","B) She is taller than her sister.","C) She is most tall than her sister.","D) She is tallest than her sister."]','B','Single-syllable adjectives use -er for comparisons, never more + -er.','{"A":"Double comparative","C":"Most is superlative and doesn''t use than","D":"Superlative form doesn''t use than"}','grammar_usage','medium','One-syllable: add -er. Two+ syllables: use more. Never combine both.'),
('a0000000-0002-0000-0000-000000000007','english','Which uses the subjunctive mood correctly?',NULL,'["A) If I was you, I would leave.","B) If I were you, I would leave.","C) If I am you, I would leave.","D) If I be you, I would leave."]','B','Subjunctive uses were for hypothetical conditions regardless of subject.','{"A":"Was is indicative, not subjunctive","C":"Am is present indicative","D":"Be is ungrammatical here"}','grammar_usage','hard','Hypothetical if-clauses use were: if I were, if she were, if it were.'),
('a0000000-0002-0000-0000-000000000008','english','Which sentence correctly uses lie vs. lay?',NULL,'["A) I need to lay down for a nap.","B) I need to lie down for a nap.","C) I lied down yesterday.","D) Lay the book on the table and lay down."]','B','Lie means to recline (no object). Lay means to put something down (needs object).','{"A":"Lay requires a direct object","C":"Lied means told untruth; past of lie-recline is lay","D":"Second lay should be lie"}','grammar_usage','hard','Lie (recline): lie, lay, lain. Lay (put down): lay, laid, laid.'),
-- sentence_structure (8 questions: 3 easy, 3 medium, 2 hard)
('a0000000-0003-0000-0000-000000000001','english','Which is a run-on sentence?',NULL,'["A) She studied hard and passed.","B) She studied hard she passed.","C) Because she studied, she passed.","D) She studied hard; she passed."]','B','Two independent clauses with no conjunction or punctuation form a run-on.','{"A":"Joined with conjunction","C":"Subordination","D":"Joined with semicolon"}','sentence_structure','easy','A run-on fuses two complete sentences without punctuation or conjunction.'),
('a0000000-0003-0000-0000-000000000002','english','Which is a complete sentence?',NULL,'["A) Running through the park quickly.","B) Although she studied all night.","C) The cat slept on the mat.","D) Because of the heavy rain."]','C','Only C has a subject (cat), verb (slept), and expresses a complete thought.','{"A":"Participial phrase—no subject","B":"Dependent clause","D":"Prepositional phrase fragment"}','sentence_structure','easy','Complete sentences need: subject + verb + complete thought.'),
('a0000000-0003-0000-0000-000000000003','english','Which correctly combines two sentences using subordination?',NULL,'["A) The rain stopped we went outside.","B) The rain stopped, we went outside.","C) After the rain stopped, we went outside.","D) The rain, stopped we went outside."]','C','After creates a dependent clause, correctly joining the ideas.','{"A":"Run-on sentence","B":"Comma splice","D":"Illogical comma"}','sentence_structure','easy','Subordinating conjunctions (after, because, although) join clauses correctly.'),
('a0000000-0003-0000-0000-000000000004','english','Which fixes this comma splice? "The experiment failed, the team started over."',NULL,'["A) The experiment failed the team started over.","B) The experiment failed; the team started over.","C) The experiment, failed the team started over.","D) The experiment failed the, team started over."]','B','A semicolon correctly joins two related independent clauses.','{"A":"Creates a run-on","C":"Random comma","D":"Illogical comma"}','sentence_structure','medium','Fix comma splices with: semicolon, period, or add a conjunction.'),
('a0000000-0003-0000-0000-000000000005','english','Which eliminates the sentence fragment? "Because she studied every night. She passed."',NULL,'["A) Because she studied every night she passed.","B) Because she studied every night, she passed.","C) She studied every night. Because she passed.","D) Because. She studied every night."]','B','Attaching the dependent clause to the independent clause with a comma fixes it.','{"A":"Missing comma after introductory clause","C":"Creates a new fragment","D":"Nonsensical"}','sentence_structure','medium','Dependent clauses cannot stand alone—attach them to an independent clause.'),
('a0000000-0003-0000-0000-000000000006','english','Which sentence correctly uses a compound-complex structure?',NULL,'["A) Although it rained, we went hiking, and we had a great time.","B) Although it rained we went hiking and we had.","C) It rained, although we went, hiking and.","D) We went although rained hiking great."]','A','One dependent clause (although it rained) + two independent clauses joined by and.','{"B":"Missing punctuation and incomplete","C":"Illogical structure","D":"Not a sentence"}','sentence_structure','medium','Compound-complex = at least one dependent clause + at least two independent clauses.'),
('a0000000-0003-0000-0000-000000000007','english','Which correctly uses a participial phrase?',NULL,'["A) Driving to work, the radio played a song.","B) Driving to work, she heard a song.","C) The radio, driving to work, played.","D) A song, driving to work, played."]','B','The participial phrase must modify the subject that follows—she is the one driving.','{"A":"Radio cannot drive—dangling modifier","C":"Radio cannot drive","D":"Song cannot drive"}','sentence_structure','hard','The noun after a participial phrase must be the one doing the action.'),
('a0000000-0003-0000-0000-000000000008','english','Which revision corrects the misplaced clause?','Original: The teacher gave a test to the students that was very difficult.',NULL,'["A) The teacher gave a test that was very difficult to the students.","B) The teacher that was very difficult gave a test.","C) To the students the teacher that gave a test was difficult.","D) Very difficult, the teacher gave a test to students."]','A','Moving that was very difficult next to test clarifies what was difficult.','{"B":"Makes teacher difficult","C":"Nonsensical","D":"Dangling modifier"}','sentence_structure','hard','Place relative clauses directly after the noun they modify.'),
-- style (7 questions: 2 easy, 3 medium, 2 hard)
('a0000000-0004-0000-0000-000000000001','english','Which sentence is most concise?',NULL,'["A) At this point in time, we need to act now.","B) We need to act now.","C) It is necessary that action be taken by us at this time.","D) Due to the fact that time is passing, we must act."]','B','Conveys the same meaning in the fewest words.','{"A":"At this point in time is wordy for now","C":"Passive and wordy","D":"Due to the fact that is wordy for because"}','style','easy','Choose the shortest option that preserves meaning.'),
('a0000000-0004-0000-0000-000000000002','english','Which is written in active voice?',NULL,'["A) The cake was eaten by the children.","B) The children ate the cake.","C) The cake was eaten.","D) It was eaten by them."]','B','Subject (children) performs the action (ate) on the object (cake).','{"A":"Passive voice","C":"Passive—no actor","D":"Passive with vague pronoun"}','style','easy','Active: subject does action. Passive: subject receives action (was/were + past participle).'),
('a0000000-0004-0000-0000-000000000003','english','Which maintains formal academic tone?','Essay: The Industrial Revolution transformed manufacturing. _____ Workers moved to factories.',NULL,'["A) It was totally wild how fast things changed.","B) The pace of change was unprecedented.","C) Stuff happened really quickly.","D) Things got crazy fast."]','B','Matches the formal academic tone of surrounding text.','{"A":"Too informal and colloquial","C":"Vague and informal","D":"Slang"}','style','medium','Match the tone of the surrounding text.'),
('a0000000-0004-0000-0000-000000000004','english','Which avoids jargon for a general audience?',NULL,'["A) The patient exhibited acute myocardial infarction.","B) The patient had a heart attack.","C) The patient''s cardiac event was myocardial.","D) The MI was acute and significant."]','B','Plain language is clearer for non-specialist readers.','{"A":"Medical terminology unclear to readers","C":"Unnecessary complexity","D":"Abbreviation unclear"}','style','medium','Use plain terms for general audiences; save jargon for specialist communication.'),
('a0000000-0004-0000-0000-000000000005','english','Which revision eliminates redundancy?',NULL,'["A) She returned back to the office.","B) She returned to the office.","C) She went back and returned to the office.","D) She returned back again to the office."]','B','Returned already means went back—adding back is redundant.','{"A":"Back is redundant with returned","C":"Double redundancy","D":"Triple redundancy"}','style','medium','Eliminate words that repeat meaning already in the sentence.'),
('a0000000-0004-0000-0000-000000000006','english','What effect does the short final sentence create?','The explorers trekked through jungle, crossed rivers, climbed mountains, and endured rain. They never quit.',NULL,'["A) It provides a specific detail.","B) It creates emphasis through contrast with the longer sentence.","C) It introduces a new topic.","D) It provides a counterargument."]','B','A short sentence after a long one creates rhetorical emphasis.','{"A":"It is a general statement","C":"Same topic","D":"Supports rather than counters"}','style','hard','Short sentences after long ones create emphasis and dramatic effect.'),
('a0000000-0004-0000-0000-000000000007','english','Which best uses active voice for clarity?',NULL,'["A) The ball was kicked by the player into the goal.","B) The player kicked the ball into the goal.","C) Into the goal the ball was kicked by the player.","D) It was the ball that was kicked into the goal."]','B','Active voice (subject-verb-object) is most direct and clear.','{"A":"Passive buries the actor","C":"Inverted passive","D":"Cleft sentence with passive"}','style','hard','Prefer subject-verb-object order for maximum clarity and impact.'),
-- organization (8 questions: 3 easy, 3 medium, 2 hard)
('a0000000-0005-0000-0000-000000000001','english','Which best begins this paragraph?','[1] _____ [2] Plastic waste kills one million seabirds yearly. [3] Chemical runoff creates ocean dead zones.',NULL,'["A) I went to the beach.","B) Ocean pollution poses severe threats to marine life.","C) Beaches are popular destinations.","D) Water covers the Earth."]','B','A topic sentence previews the paragraph subject: ocean pollution threats.','{"A":"Irrelevant personal detail","C":"About recreation not pollution","D":"Too broad"}','organization','easy','Topic sentences introduce what the paragraph discusses.'),
('a0000000-0005-0000-0000-000000000002','english','Which concluding sentence best fits?','Exercise improves heart health, strengthens bones, and boosts mood. It also reduces chronic disease risk.',NULL,'["A) Everyone should eat vegetables.","B) Regular exercise offers comprehensive health benefits.","C) Swimming is the best exercise.","D) Some people dislike exercise."]','B','Summarizes the main point of the paragraph.','{"A":"About diet not exercise","C":"Too specific","D":"Introduces counterpoint without resolution"}','organization','easy','Conclusions restate or synthesize the paragraph''s main idea.'),
('a0000000-0005-0000-0000-000000000003','english','Which transition connects cause to effect?','The restaurant got rave reviews. _____ Reservations are booked months ahead.',NULL,'["A) Meanwhile,","B) As a result,","C) In contrast,","D) For example,"]','B','As a result shows that high demand is caused by good reviews.','{"A":"Shows time not causation","C":"Shows opposition","D":"Shows illustration"}','organization','easy','Cause-effect: as a result, consequently, therefore, thus.'),
('a0000000-0005-0000-0000-000000000004','english','Where should Sentence 3 go for logical order?','[1] The board proposed a dress code. [2] Students petitioned against it. [3] The policy was revised. [4] Parents voiced opinions.',NULL,'["A) Where it is now","B) Before Sentence 1","C) After Sentence 4","D) Between 1 and 2"]','C','Logical order: proposal, petition, parent opinions, then revision (resolution last).','{"A":"Revision before parent input is illogical","B":"Revision before proposal is illogical","D":"Revision before reactions is illogical"}','organization','medium','Arrange events chronologically: cause before effect, action before reaction.'),
('a0000000-0005-0000-0000-000000000005','english','Which sentence best adds evidence?','Urban gardens have become increasingly important. _____ Cities are investing in garden programs.',NULL,'["A) People enjoy gardening.","B) A 2024 study found neighborhoods with gardens saw 15% higher satisfaction.","C) Gardens are relaxing.","D) Some prefer flowers over vegetables."]','B','Specific data (study with percentage) provides concrete evidence.','{"A":"Vague opinion","C":"Subjective observation","D":"Irrelevant preference"}','organization','medium','Strong evidence includes numbers, studies, or concrete examples.'),
('a0000000-0005-0000-0000-000000000006','english','Which transition connects contrasting paragraphs?','Paragraph 1 ends: These benefits make solar energy attractive. Paragraph 2 begins: _____ installation costs remain a barrier.',NULL,'["A) Furthermore,","B) Nevertheless,","C) Similarly,","D) For instance,"]','B','Nevertheless signals contrast between benefits and remaining challenges.','{"A":"Adds similar info","C":"Shows comparison","D":"Gives example"}','organization','medium','Contrast transitions: however, nevertheless, on the other hand, despite this.'),
('a0000000-0005-0000-0000-000000000007','english','Which best supports an argument for library funding?',NULL,'["A) Libraries are quiet.","B) Libraries have books.","C) Every dollar invested returns $5.50 in community benefit.","D) Some libraries are old."]','C','Quantifiable evidence (dollar return) directly supports the funding argument.','{"A":"Descriptive not persuasive","B":"Obvious fact","D":"Could argue against funding"}','organization','hard','Strong arguments use specific, quantifiable evidence.'),
('a0000000-0005-0000-0000-000000000008','english','Which sentence order creates the most logical paragraph?','Sentences: [A] The hypothesis was confirmed. [B] Researchers designed an experiment. [C] They collected and analyzed data. [D] Scientists observed an unexpected pattern.',NULL,'["A) D, B, C, A","B) A, B, C, D","C) B, C, D, A","D) C, A, B, D"]','A','Scientific method order: observation, experiment design, data collection, conclusion.','{"B":"Conclusion first is illogical","C":"Design before observation","D":"Random order"}','organization','hard','Follow logical sequences: observation, hypothesis, experiment, data, conclusion.'),
-- word_choice (8 questions: 3 easy, 3 medium, 2 hard)
('a0000000-0006-0000-0000-000000000001','english','Which word best completes: "The sunset was _____ beautiful."',NULL,'["A) real","B) really","C) realy","D) reely"]','B','Really is an adverb that correctly modifies the adjective beautiful.','{"A":"Adjective cannot modify adjective","C":"Misspelling","D":"Misspelling"}','word_choice','easy','Use adverbs (really, very) to modify adjectives.'),
('a0000000-0006-0000-0000-000000000002','english','Which transition shows cause-effect?',NULL,'["A) Meanwhile","B) Nevertheless","C) Consequently","D) Similarly"]','C','Consequently signals that what follows is a result of what came before.','{"A":"Shows time","B":"Shows contrast","D":"Shows comparison"}','word_choice','easy','Cause-effect: consequently, therefore, as a result, thus, hence.'),
('a0000000-0006-0000-0000-000000000003','english','What does apprehensive mean here? "Students were apprehensive about the exam."',NULL,'["A) excited","B) anxious","C) indifferent","D) confident"]','B','Apprehensive means anxious or worried about something upcoming.','{"A":"Positive anticipation not worry","C":"Means not caring","D":"Opposite meaning"}','word_choice','easy','Context clue: exams cause stress, so the word likely means worried.'),
('a0000000-0006-0000-0000-000000000004','english','Which is most precise? "The detective carefully _____ the crime scene."',NULL,'["A) looked at","B) examined","C) saw","D) watched"]','B','Examined implies careful detailed inspection matching the context.','{"A":"Too casual and vague","C":"Passive observation","D":"Implies watching over time"}','word_choice','medium','Choose the most specific word that fits the context and tone.'),
('a0000000-0006-0000-0000-000000000005','english','Which replaces good with a more precise word? "The orchestra gave a good performance."',NULL,'["A) nice","B) stellar","C) okay","D) fine"]','B','Stellar is vivid and precise, conveying excellence.','{"A":"Equally vague","C":"Weaker than good","D":"Weaker than good"}','word_choice','medium','Replace vague words (good, bad, nice) with vivid, precise alternatives.'),
('a0000000-0006-0000-0000-000000000006','english','Which word fits the formal context? "The committee will _____ the proposal next week."',NULL,'["A) look at","B) check out","C) review","D) scope out"]','C','Review is appropriately formal for a committee context.','{"A":"Too informal","B":"Colloquial","D":"Slang"}','word_choice','medium','Match word formality to the context: formal writing needs formal vocabulary.'),
('a0000000-0006-0000-0000-000000000007','english','The effects of the policy _____ felt across the community.',NULL,'["A) were","B) was","C) is","D) has been"]','A','Effects is plural requiring plural verb were.','{"B":"Singular with plural subject","C":"Singular present with plural subject","D":"Singular auxiliary with plural subject"}','word_choice','hard','Don''t confuse effects (noun, plural) with affects (verb).'),
('a0000000-0006-0000-0000-000000000008','english','Which word conveys the intended nuance? "The diplomat spoke with _____ precision."',NULL,'["A) ruthless","B) careful","C) surgical","D) okay"]','C','Surgical precision is an idiom conveying extreme exactness and skill.','{"A":"Implies cruelty not skill","B":"Too generic","D":"Informal and imprecise"}','word_choice','hard','Connotation matters: choose words whose associations match your meaning.'),
-- verb_tense (8 questions: 3 easy, 2 medium, 3 hard)
('a0000000-0007-0000-0000-000000000001','english','Which uses correct tense? "By the time we arrived, the movie _____."',NULL,'["A) started","B) had started","C) has started","D) will start"]','B','Past perfect (had started) shows one past event before another.','{"A":"Simple past doesn''t show sequence","C":"Present perfect with past context","D":"Future with past context"}','verb_tense','easy','Past perfect (had + past participle) = earlier of two past events.'),
('a0000000-0007-0000-0000-000000000002','english','Which maintains consistent tense?','She opens the door, sees the package, picks it up, and _____ inside.',NULL,'["A) walked","B) walks","C) will walk","D) had walked"]','B','Paragraph is in present tense; walks maintains consistency.','{"A":"Past breaks consistency","C":"Future breaks consistency","D":"Past perfect breaks consistency"}','verb_tense','easy','Keep verbs in the same tense unless timeline logically shifts.'),
('a0000000-0007-0000-0000-000000000003','english','Time indicator next month requires which tense? "The team _____ their findings next month."',NULL,'["A) presented","B) presents","C) will present","D) had presented"]','C','Next month is future; will present is correct.','{"A":"Past tense with future indicator","B":"Present doesn''t match future indicator","D":"Past perfect with future indicator"}','verb_tense','easy','Time words (yesterday, now, next week) indicate which tense to use.'),
('a0000000-0007-0000-0000-000000000004','english','Which correctly shifts tense for a sequence?',NULL,'["A) She will graduate next year and got a job.","B) She graduated last year and will start next month.","C) She graduates last year and will got.","D) She will graduated and gets a job."]','B','Past (graduated last year) to future (will start next month) is logical.','{"A":"Illogical future-to-past shift","C":"Wrong forms","D":"Incorrect verb forms"}','verb_tense','medium','Tense shifts are okay when the timeline logically requires them.'),
('a0000000-0007-0000-0000-000000000005','english','Which uses present perfect correctly?',NULL,'["A) I have went to Paris twice.","B) I have gone to Paris twice.","C) I have go to Paris twice.","D) I has gone to Paris twice."]','B','Present perfect = have/has + past participle. Gone is the past participle of go.','{"A":"Went is past tense not participle","C":"Go is base form not participle","D":"Has with I is incorrect"}','verb_tense','medium','Present perfect: have/has + past participle (gone, written, seen).'),
('a0000000-0007-0000-0000-000000000006','english','Which uses future perfect correctly?',NULL,'["A) By Friday, I will have completed the project.","B) By Friday, I will complete the project.","C) By Friday, I completed the project.","D) By Friday, I have completed the project."]','A','Future perfect (will have + participle) = completed before a future time.','{"B":"Simple future doesn''t emphasize before-deadline completion","C":"Past with future marker","D":"Present perfect with future marker"}','verb_tense','hard','Future perfect = will have + past participle. Action done before a future deadline.'),
('a0000000-0007-0000-0000-000000000007','english','Which correctly uses past perfect progressive?',NULL,'["A) She had been studying for hours before the test.","B) She has been studied for hours before the test.","C) She had been study for hours before the test.","D) She was had studying for hours."]','A','Past perfect progressive (had been + -ing) shows ongoing action before a past event.','{"B":"Wrong form","C":"Missing -ing form","D":"Incorrect structure"}','verb_tense','hard','Had been + -ing = ongoing past action before another past event.'),
('a0000000-0007-0000-0000-000000000008','english','Which tense is appropriate for a general scientific fact?',NULL,'["A) Water boiled at 100 degrees Celsius.","B) Water boils at 100 degrees Celsius.","C) Water will boil at 100 degrees.","D) Water has boiled at 100 degrees."]','B','General scientific truths use simple present tense.','{"A":"Past implies it no longer does","C":"Future implies it doesn''t yet","D":"Present perfect implies recent action"}','verb_tense','hard','Universal truths and scientific facts use simple present tense.'),
-- pronoun_agreement (8 questions: 3 easy, 3 medium, 2 hard)
('a0000000-0008-0000-0000-000000000001','english','Which has correct pronoun-antecedent agreement?',NULL,'["A) Each student must bring their pencil.","B) Each student must bring his or her pencil.","C) Each student must bring our pencil.","D) Each student must bring your pencil."]','B','Each student is singular; his or her is the traditional singular match.','{"A":"Their traditionally plural for singular antecedent","C":"Our doesn''t match","D":"Your doesn''t match"}','pronoun_agreement','easy','Singular antecedent = singular pronoun.'),
('a0000000-0008-0000-0000-000000000002','english','Which has a clear pronoun reference?',NULL,'["A) The book was on the table but it was dusty.","B) The company announced they were hiring.","C) After John called Mike, he left.","D) The dog chased its tail."]','D','Its clearly refers to dog—only one possible antecedent.','{"A":"It could be book or table","B":"They is plural for singular company","C":"He could be John or Mike"}','pronoun_agreement','easy','Each pronoun should have only one possible antecedent.'),
('a0000000-0008-0000-0000-000000000003','english','Which pronoun correctly refers to the antecedent? "The team celebrated _____ victory."',NULL,'["A) their","B) its","C) his","D) your"]','B','Team is a singular collective noun; its is singular possessive for things/groups.','{"A":"Traditionally plural for singular noun","C":"His implies a person not a group","D":"Your doesn''t match"}','pronoun_agreement','easy','Collective nouns (team, committee) are singular and take it/its.'),
('a0000000-0008-0000-0000-000000000004','english','Which fixes the ambiguous pronoun?','When Sarah told Maria about the award, she was thrilled.',NULL,'["A) When Sarah told Maria, Sarah was thrilled.","B) She was thrilled when told.","C) Thrilled, she told Maria.","D) Sarah and she were thrilled."]','A','Replacing she with Sarah removes ambiguity.','{"B":"She still ambiguous","C":"Changes meaning","D":"Still unclear"}','pronoun_agreement','medium','Replace ambiguous pronouns with the specific noun.'),
('a0000000-0008-0000-0000-000000000005','english','Which correctly uses a reflexive pronoun?',NULL,'["A) The project was completed by John and myself.","B) The project was completed by John and me.","C) Myself completed the project.","D) The project completed itself and myself."]','B','Reflexive pronouns (myself) are only for when subject and object are the same person.','{"A":"Myself is not correct as object of by","C":"Myself cannot be a subject","D":"Nonsensical reflexive use"}','pronoun_agreement','medium','Use myself only when you are both subject and object: I hurt myself.'),
('a0000000-0008-0000-0000-000000000006','english','Which sentence has correct pronoun case after a preposition?',NULL,'["A) Between you and I, this is wrong.","B) Between you and me, this is wrong.","C) Between you and myself.","D) Between I and you."]','B','After prepositions, use object pronouns: me, him, her, us, them.','{"A":"I is subject form, not object","C":"Myself is reflexive not object of preposition","D":"I is subject form"}','pronoun_agreement','medium','Prepositions take object pronouns: to me, for her, between us.'),
('a0000000-0008-0000-0000-000000000007','english','Which handles pronouns with compound antecedents correctly?',NULL,'["A) Neither the manager nor the employees got their bonus.","B) Neither the manager nor the employees got his bonus.","C) Neither the manager nor the employees got its bonus.","D) Neither the manager nor the employees got our bonus."]','A','With neither/nor, pronoun agrees with nearer antecedent (employees = their).','{"B":"His doesn''t match employees","C":"Its for things not people","D":"Our doesn''t match"}','pronoun_agreement','hard','With neither/nor, the pronoun agrees with the nearer antecedent.'),
('a0000000-0008-0000-0000-000000000008','english','Which correctly handles pronoun reference across clauses?',NULL,'["A) When a person studies hard, you will succeed.","B) When a person studies hard, they will succeed.","C) When a person studies hard, he or she will succeed.","D) When you study hard, a person will succeed."]','C','Consistent reference: a person...he or she. No shift in person.','{"A":"Shifts from third person to second person","B":"Acceptable colloquially but traditional grammar prefers C","D":"Shifts person illogically"}','pronoun_agreement','hard','Don''t shift person: if you start with a person use he/she, not you.'),
-- modifier_placement (7 questions: 2 easy, 3 medium, 2 hard)
('a0000000-0009-0000-0000-000000000001','english','Which places the modifier correctly?',NULL,'["A) She almost drove 300 miles.","B) She drove almost 300 miles.","C) Almost she drove 300 miles.","D) She drove 300 almost miles."]','B','Almost modifies 300 miles (the distance), not the verb drove.','{"A":"Implies she nearly drove but didn''t","C":"Awkward placement","D":"Cannot modify miles alone"}','modifier_placement','easy','Place modifiers directly next to the word they limit.'),
('a0000000-0009-0000-0000-000000000002','english','Which fixes this dangling modifier? "Walking to school, the rain began."',NULL,'["A) Walking to school, it rained.","B) While I was walking to school, the rain began.","C) The rain, walking to school, began.","D) Walking to school began the rain."]','B','Adding the logical subject (I) fixes the dangling modifier.','{"A":"It cannot walk","C":"Rain cannot walk","D":"Nonsensical"}','modifier_placement','easy','If modifier doesn''t match subject, rewrite to include the correct actor.'),
('a0000000-0009-0000-0000-000000000003','english','Which fixes: "The teacher handed papers to students covered in red ink."',NULL,'["A) The teacher handed papers covered in red ink to students.","B) Covered in red ink, the teacher handed papers.","C) The students covered in red ink got papers.","D) Papers, to students covered in ink, the teacher handed."]','A','Moving covered in red ink next to papers clarifies meaning.','{"B":"Teacher is covered in ink","C":"Students are covered in ink","D":"Incomprehensible"}','modifier_placement','medium','Place modifying phrases next to what they describe.'),
('a0000000-0009-0000-0000-000000000004','english','Where should only go to mean the food cost $5? "She _____ paid _____ five dollars _____ for the meal _____."',NULL,'["A) only...___...___...___","B) ___...only...___...___","C) ___...___...only...___","D) ___...___...___...only"]','C','Only before five dollars limits the amount.','{"A":"Implies she only paid (didn''t eat)","B":"Implies she only paid (didn''t eat)","D":"Implies only for the meal (not other purchases)"}','modifier_placement','medium','Only directly before the word it limits changes meaning.'),
('a0000000-0009-0000-0000-000000000005','english','Which avoids a squinting modifier? "Students who study frequently pass exams."',NULL,'["A) Students who frequently study pass exams.","B) Students who study pass exams frequently.","C) Frequently, students who study pass exams.","D) All of the above clarify the meaning."]','D','The original is ambiguous—frequently could modify study or pass. All three revisions resolve it differently but each is clear.','{"A":"Clear but changes meaning slightly","B":"Clear but changes meaning slightly","C":"Clear but changes meaning slightly"}','modifier_placement','medium','A squinting modifier sits between two words it could modify—move it to remove ambiguity.'),
('a0000000-0009-0000-0000-000000000006','english','Which avoids a dangling modifier?',NULL,'["A) After finishing the exam, the room felt empty.","B) After finishing the exam, the students left.","C) Finishing the exam, relief was felt.","D) Having finished, the papers were collected."]','B','Only B has the logical subject (students) immediately after the participial phrase.','{"A":"Room cannot finish exam","C":"Relief cannot finish exam","D":"Papers cannot finish exam"}','modifier_placement','hard','Participial phrases must be followed by their logical subject.'),
('a0000000-0009-0000-0000-000000000007','english','Which correctly places a limiting modifier in a formal sentence?',NULL,'["A) The committee merely reviewed three proposals.","B) The committee reviewed merely three proposals.","C) Merely, the committee reviewed three proposals.","D) The committee reviewed three merely proposals."]','B','Merely limits three proposals (only three), which is the intended meaning.','{"A":"Merely modifies reviewed—they just reviewed","C":"Ambiguous placement","D":"Cannot modify proposals that way"}','modifier_placement','hard','Limiting modifiers (only, merely, just) must be right before what they limit.'),
-- parallelism (7 questions: 2 easy, 3 medium, 2 hard)
('a0000000-0010-0000-0000-000000000001','english','Which list uses parallel structure?',NULL,'["A) She likes swimming, to hike, and biking.","B) She likes swimming, hiking, and biking.","C) She likes to swim, hiking, and to bike.","D) She likes swimming, hikes, and to bike."]','B','All gerunds: swimming, hiking, biking. Same grammatical form.','{"A":"Mixes gerund, infinitive, gerund","C":"Mixes infinitive, gerund, infinitive","D":"Mixes gerund, verb, infinitive"}','parallelism','easy','List items must share the same grammatical form.'),
('a0000000-0010-0000-0000-000000000002','english','Which comparison uses parallel structure?',NULL,'["A) Running a marathon is harder than to sprint.","B) Running a marathon is harder than sprinting.","C) To run a marathon is harder than sprinting.","D) Running is more hard than a sprint."]','B','Both sides use gerunds: running...sprinting.','{"A":"Gerund vs infinitive","C":"Infinitive vs gerund","D":"Incorrect comparative and mismatched forms"}','parallelism','easy','Comparisons: gerund to gerund, noun to noun, clause to clause.'),
('a0000000-0010-0000-0000-000000000003','english','Which revision makes this parallel? "The job requires typing, answering phones, and to file documents."',NULL,'["A) typing, answering phones, and filing documents","B) to type, answering phones, and filing","C) typing, to answer phones, and filing","D) type, phones answered, and files"]','A','All gerunds: typing, answering, filing.','{"B":"Mixes infinitive and gerunds","C":"Mixes gerund and infinitive","D":"Inconsistent forms and incomplete"}','parallelism','medium','Convert all items to the same form—usually the form of the first item.'),
('a0000000-0010-0000-0000-000000000004','english','Which sentence has correct parallel structure with correlatives?',NULL,'["A) Either study hard or failing.","B) Either study hard or fail.","C) Either studying hard or fail.","D) Either to study or failing."]','B','Both elements after either/or match: study (imperative)...fail (imperative).','{"A":"Imperative vs gerund","C":"Gerund vs imperative","D":"Infinitive vs gerund"}','parallelism','medium','After either/or, both elements must have matching forms.'),
('a0000000-0010-0000-0000-000000000005','english','Which maintains parallelism in a bulleted format? "Our goals: increase sales, _____, and attract talent."',NULL,'["A) the reduction of costs","B) reducing costs","C) reduce costs","D) costs should be reduced"]','C','Increase...reduce...attract are all bare infinitives matching the pattern.','{"A":"Noun phrase doesn''t match verbs","B":"Gerund doesn''t match infinitives","D":"Full clause doesn''t match"}','parallelism','medium','Match the grammatical form of other items in the series.'),
('a0000000-0010-0000-0000-000000000006','english','Which makes this parallel? "The CEO said profits were up, morale improved, and employee retention was high."',NULL,'["A) The CEO said that profits were up, that morale improved, and that retention was high.","B) The CEO said profits, morale, retention.","C) That profits, morale improved, retention high.","D) The CEO profits up morale improved retention."]','A','Repeating that before each clause creates parallel subordinate structure.','{"B":"Incomplete","C":"Fragment","D":"Not a sentence"}','parallelism','hard','Repeated structural elements (that...that...that) create clear parallelism.'),
('a0000000-0010-0000-0000-000000000007','english','Which demonstrates correct parallelism with not only...but also?',NULL,'["A) Not only did she win but also setting a record.","B) Not only did she win the race, but she also set a record.","C) Not only winning but also she set a record.","D) She not only but also won and set."]','B','Both parts have parallel clause structure: did she win...she also set.','{"A":"Clause vs gerund phrase","C":"Gerund vs clause","D":"Incomprehensible"}','parallelism','hard','Not only...but also: ensure both sides have matching structure.'),

-- ═══════════════════════════════════════════════════════════════════════════════
-- MATH QUESTIONS (60 total)
-- ═══════════════════════════════════════════════════════════════════════════════

-- pre_algebra (6 questions: 2 easy, 2 medium, 2 hard)
('a0000000-0011-0000-0000-000000000001','math','What is 3/4 + 1/6?',NULL,'["A) 4/10","B) 11/12","C) 4/6","D) 1/2"]','B','LCD is 12: 9/12 + 2/12 = 11/12.','{"A":"Added numerators and denominators","C":"Wrong conversion","D":"Wrong calculation"}','pre_algebra','easy','Find LCD, convert fractions, then add numerators.'),
('a0000000-0011-0000-0000-000000000002','math','What is 15% of 80?',NULL,'["A) 10","B) 12","C) 15","D) 8"]','B','15% of 80 = 0.15 x 80 = 12.','{"A":"Calculated 12.5% of 80","C":"Confused percent with answer","D":"Calculated 10% of 80"}','pre_algebra','easy','Convert percent to decimal (divide by 100) then multiply.'),
('a0000000-0011-0000-0000-000000000003','math','If a recipe needs 2/3 cup sugar and you triple it, how much sugar?',NULL,'["A) 1 cup","B) 2 cups","C) 6/3 cups","D) 2/9 cup"]','B','2/3 x 3 = 6/3 = 2 cups.','{"A":"Only doubled","C":"Unsimplified but same as B","D":"Divided instead of multiplied"}','pre_algebra','medium','Multiply the fraction by the scaling factor.'),
('a0000000-0011-0000-0000-000000000004','math','Order from least to greatest: 0.5, 3/8, 0.45, 1/2',NULL,'["A) 3/8, 0.45, 0.5, 1/2","B) 0.45, 3/8, 1/2, 0.5","C) 3/8, 0.45, 1/2, 0.5","D) 1/2, 0.5, 0.45, 3/8"]','A','3/8=0.375, 0.45, 0.5=1/2. So 0.375 < 0.45 < 0.5 = 0.5.','{"B":"3/8 is less than 0.45","C":"1/2 equals 0.5 so they tie","D":"Reversed order"}','pre_algebra','medium','Convert all to decimals to compare easily.'),
('a0000000-0011-0000-0000-000000000005','math','What is the value of 2^(-3)?',NULL,'["A) -8","B) -6","C) 1/8","D) 8"]','C','2^(-3) = 1/2^3 = 1/8. Negative exponent = reciprocal.','{"A":"Applied negative to result","B":"Multiplied base by exponent","D":"Ignored negative"}','pre_algebra','hard','Negative exponent: a^(-n) = 1/a^n.'),
('a0000000-0011-0000-0000-000000000006','math','Simplify: (2^3)(2^4)/2^5',NULL,'["A) 2","B) 4","C) 8","D) 16"]','B','(2^3)(2^4) = 2^7. 2^7/2^5 = 2^2 = 4.','{"A":"Subtracted exponents wrong","C":"Didn''t divide","D":"Added all exponents"}','pre_algebra','hard','Multiply: add exponents. Divide: subtract exponents.'),

-- elementary_algebra (6 questions: 2 easy, 2 medium, 2 hard)
('a0000000-0012-0000-0000-000000000001','math','Solve: 3x - 7 = 14',NULL,'["A) 7","B) 3","C) 21","D) -7"]','A','3x = 21, x = 7.','{"B":"Divided by 7 instead of 3","C":"Forgot to divide","D":"Subtracted wrong"}','elementary_algebra','easy','Add 7 to both sides, then divide by 3.'),
('a0000000-0012-0000-0000-000000000002','math','Solve: 2(x + 3) = 16',NULL,'["A) 5","B) 6.5","C) 8","D) 4"]','A','2x + 6 = 16, 2x = 10, x = 5.','{"B":"Divided 16 by 2 then subtracted 1","C":"Only divided by 2","D":"Subtracted 3 from 8"}','elementary_algebra','easy','Distribute first, then isolate x.'),
('a0000000-0012-0000-0000-000000000003','math','Solve the system: x + y = 10 and x - y = 4. Find x.',NULL,'["A) 3","B) 7","C) 6","D) 14"]','B','Add equations: 2x = 14, x = 7.','{"A":"Found y not x","C":"Averaged 10 and 4","D":"Didn''t divide by 2"}','elementary_algebra','medium','Add or subtract equations to eliminate a variable.'),
('a0000000-0012-0000-0000-000000000004','math','Factor: 2x^2 + 7x + 3',NULL,'["A) (2x+1)(x+3)","B) (2x+3)(x+1)","C) (x+1)(x+3)","D) (2x-1)(x-3)"]','A','(2x+1)(x+3) = 2x^2 + 6x + x + 3 = 2x^2 + 7x + 3. Check.','{"B":"Gives 2x^2+5x+3","C":"Missing leading coefficient","D":"Wrong signs"}','elementary_algebra','medium','For ax^2+bx+c, find factors of ac that sum to b.'),
('a0000000-0012-0000-0000-000000000005','math','If f(x)=2x+1 and g(x)=x^2, what is f(g(3))?',NULL,'["A) 19","B) 49","C) 7","D) 13"]','A','g(3)=9, f(9)=2(9)+1=19.','{"B":"Computed g(f(3))","C":"Only computed f(3)","D":"Added instead of composing"}','elementary_algebra','hard','Composition: compute inner function first, then apply outer.'),
('a0000000-0012-0000-0000-000000000006','math','Solve: |2x - 6| = 10',NULL,'["A) x=8 or x=-2","B) x=8 only","C) x=2 or x=-2","D) x=8 or x=2"]','A','2x-6=10 gives x=8. 2x-6=-10 gives x=-2.','{"B":"Forgot negative case","C":"Error in positive case","D":"Error in negative case"}','elementary_algebra','hard','Absolute value: split into positive and negative cases.'),
-- intermediate_algebra (6 questions: 2 easy, 2 medium, 2 hard)
('a0000000-0013-0000-0000-000000000001','math','What are the solutions to x^2 - 5x + 6 = 0?',NULL,'["A) x=2 and x=3","B) x=-2 and x=-3","C) x=1 and x=6","D) x=-1 and x=-6"]','A','Factor: (x-2)(x-3)=0. Solutions: x=2, x=3.','{"B":"Wrong signs","C":"Wrong factors","D":"Wrong factors"}','intermediate_algebra','easy','Find two numbers that multiply to 6 and add to -5.'),
('a0000000-0013-0000-0000-000000000002','math','Simplify: sqrt(48)',NULL,'["A) 4*sqrt(3)","B) 2*sqrt(12)","C) 6*sqrt(2)","D) 3*sqrt(4)"]','A','sqrt(48) = sqrt(16*3) = 4*sqrt(3).','{"B":"Not fully simplified","C":"Wrong factoring","D":"sqrt(4)=2, needs more simplification"}','intermediate_algebra','easy','Find largest perfect square factor: 48=16x3.'),
('a0000000-0013-0000-0000-000000000003','math','If log_2(x) = 5, what is x?',NULL,'["A) 10","B) 25","C) 32","D) 64"]','C','log_2(x)=5 means 2^5=x=32.','{"A":"Multiplied 2x5","B":"Computed 5^2","D":"Computed 2^6"}','intermediate_algebra','medium','log_b(x)=y means b^y=x. Convert to exponential form.'),
('a0000000-0013-0000-0000-000000000004','math','What is the sum of arithmetic sequence 2, 5, 8, ..., 29?',NULL,'["A) 145","B) 155","C) 160","D) 175"]','B','d=3, n=(29-2)/3+1=10. S=10(2+29)/2=155.','{"A":"Wrong number of terms","C":"Wrong formula","D":"Wrong count"}','intermediate_algebra','medium','Arithmetic series: S = n(first+last)/2.'),
('a0000000-0013-0000-0000-000000000005','math','If g(x)=x^3-4x, what are the zeros?',NULL,'["A) 0, 2, -2","B) 0, 4","C) 2, -2","D) 0, 4, -4"]','A','Factor: x(x^2-4)=x(x+2)(x-2). Zeros: 0, 2, -2.','{"B":"Incomplete factoring","C":"Missed x=0","D":"Wrong factoring"}','intermediate_algebra','hard','Factor out GCF first, then use difference of squares.'),
('a0000000-0013-0000-0000-000000000006','math','Solve: x^2 + 2x - 15 = 0 using the quadratic formula.',NULL,'["A) x=3 or x=-5","B) x=-3 or x=5","C) x=3 or x=5","D) x=-3 or x=-5"]','A','x=(-2 +/- sqrt(4+60))/2 = (-2+/-8)/2. x=3 or x=-5.','{"B":"Sign errors","C":"Both positive impossible since c is negative","D":"Both negative impossible"}','intermediate_algebra','hard','Quadratic formula: x=(-b +/- sqrt(b^2-4ac))/2a.'),

-- coordinate_geometry (6 questions: 2 easy, 2 medium, 2 hard)
('a0000000-0014-0000-0000-000000000001','math','What is the slope of the line through (1,2) and (5,10)?',NULL,'["A) 1","B) 2","C) 4","D) 8"]','B','Slope=(10-2)/(5-1)=8/4=2.','{"A":"Subtracted wrong","C":"Used only y-difference","D":"Used only numerator"}','coordinate_geometry','easy','Slope = rise/run = (y2-y1)/(x2-x1).'),
('a0000000-0014-0000-0000-000000000002','math','What is the midpoint of (2,4) and (8,10)?',NULL,'["A) (5,7)","B) (4,7)","C) (6,14)","D) (10,14)"]','A','Midpoint=((2+8)/2,(4+10)/2)=(5,7).','{"B":"Error in x","C":"Didn''t divide y","D":"Didn''t divide either"}','coordinate_geometry','easy','Midpoint: average the x-coordinates and y-coordinates separately.'),
('a0000000-0014-0000-0000-000000000003','math','What is the equation of a line with slope 3 through (2,1)?',NULL,'["A) y=3x-5","B) y=3x+1","C) y=3x-1","D) y=3x+5"]','A','y-1=3(x-2), y-1=3x-6, y=3x-5.','{"B":"Used y-coord as intercept","C":"Sign error","D":"Added instead of subtracted"}','coordinate_geometry','medium','Point-slope form: y-y1=m(x-x1), then solve for y.'),
('a0000000-0014-0000-0000-000000000004','math','What is the distance between (0,0) and (3,4)?',NULL,'["A) 5","B) 7","C) 25","D) 12"]','A','d=sqrt(9+16)=sqrt(25)=5.','{"B":"Added coordinates","C":"Forgot square root","D":"Multiplied coordinates"}','coordinate_geometry','medium','Distance formula: d=sqrt((x2-x1)^2+(y2-y1)^2).'),
('a0000000-0014-0000-0000-000000000005','math','Which is the equation of a circle with center (3,-2) and radius 5?',NULL,'["A) (x-3)^2+(y+2)^2=25","B) (x+3)^2+(y-2)^2=25","C) (x-3)^2+(y-2)^2=5","D) (x+3)^2+(y+2)^2=5"]','A','Circle: (x-h)^2+(y-k)^2=r^2. Center(3,-2), r=5, so r^2=25.','{"B":"Signs reversed","C":"Didn''t square radius","D":"Both errors"}','coordinate_geometry','hard','Circle equation: (x-h)^2+(y-k)^2=r^2. Note the subtraction in the formula.'),
('a0000000-0014-0000-0000-000000000006','math','Find the x-intercept of 2x + 3y = 12.',NULL,'["A) (6,0)","B) (0,4)","C) (4,0)","D) (0,6)"]','A','Set y=0: 2x=12, x=6. X-intercept is (6,0).','{"B":"Found y-intercept","C":"Divided by 3 not 2","D":"Found y-intercept wrong"}','coordinate_geometry','hard','X-intercept: set y=0 and solve for x.'),
-- plane_geometry (6 questions: 2 easy, 2 medium, 2 hard)
('a0000000-0015-0000-0000-000000000001','math','What is the area of a rectangle with length 8 and width 5?',NULL,'["A) 13","B) 26","C) 40","D) 80"]','C','Area = length x width = 8 x 5 = 40.','{"A":"Added instead of multiplied","B":"Calculated perimeter","D":"Multiplied by 2 extra"}','plane_geometry','easy','Rectangle area = length x width. Perimeter = 2(l+w).'),
('a0000000-0015-0000-0000-000000000002','math','A triangle has angles 50 and 65 degrees. What is the third angle?',NULL,'["A) 55","B) 65","C) 75","D) 115"]','B','180-50-65=65 degrees.','{"A":"Subtraction error","C":"Subtracted wrong values","D":"Forgot to subtract both"}','plane_geometry','easy','Triangle angles sum to 180 degrees.'),
('a0000000-0015-0000-0000-000000000003','math','In a right triangle with legs 6 and 8, what is the hypotenuse?',NULL,'["A) 10","B) 14","C) 48","D) 100"]','A','c^2=36+64=100, c=10.','{"B":"Added legs","C":"Multiplied legs","D":"Didn''t take square root"}','plane_geometry','medium','Pythagorean theorem: c^2=a^2+b^2. 6-8-10 is a common triple.'),
('a0000000-0015-0000-0000-000000000004','math','What is the area of a circle with radius 6?',NULL,'["A) 12pi","B) 36pi","C) 6pi","D) 144pi"]','B','Area=pi*r^2=pi*36=36pi.','{"A":"Used 2*pi*r (circumference formula)","C":"Used pi*r","D":"Squared the diameter"}','plane_geometry','medium','Circle area = pi*r^2. Don''t confuse with circumference = 2*pi*r.'),
('a0000000-0015-0000-0000-000000000005','math','Two similar triangles have a scale factor of 3:1. If the smaller has area 4, what is the larger area?',NULL,'["A) 12","B) 36","C) 16","D) 9"]','B','Area scales by square of scale factor: 4 x 3^2 = 4 x 9 = 36.','{"A":"Multiplied by 3 not 9","C":"Multiplied by 4","D":"Just squared the factor"}','plane_geometry','hard','Similar figures: length scales by k, area by k^2, volume by k^3.'),
('a0000000-0015-0000-0000-000000000006','math','What is the volume of a cylinder with radius 3 and height 8?',NULL,'["A) 24pi","B) 48pi","C) 72pi","D) 192pi"]','C','V=pi*r^2*h=pi*9*8=72pi.','{"A":"Used 2*pi*r*h","B":"Used pi*r^2 with r=2","D":"Squared both r and h"}','plane_geometry','hard','Cylinder volume = pi*r^2*h. Square the radius first.'),

-- trigonometry (6 questions: 2 easy, 2 medium, 2 hard)
('a0000000-0016-0000-0000-000000000001','math','In a right triangle, if the opposite side is 3 and hypotenuse is 5, what is sin(theta)?',NULL,'["A) 3/5","B) 4/5","C) 5/3","D) 3/4"]','A','sin = opposite/hypotenuse = 3/5.','{"B":"This is cos","C":"Reciprocal","D":"Opposite/adjacent is tan"}','trigonometry','easy','SOH-CAH-TOA: Sin=Opp/Hyp, Cos=Adj/Hyp, Tan=Opp/Adj.'),
('a0000000-0016-0000-0000-000000000002','math','Convert 180 degrees to radians.',NULL,'["A) pi/2","B) pi","C) 2pi","D) pi/4"]','B','180 degrees = pi radians.','{"A":"This is 90 degrees","C":"This is 360 degrees","D":"This is 45 degrees"}','trigonometry','easy','180 degrees = pi radians. Multiply degrees by pi/180.'),
('a0000000-0016-0000-0000-000000000003','math','If sin(theta)=3/5, what is cos(theta) in the first quadrant?',NULL,'["A) 3/5","B) 4/5","C) 5/3","D) 5/4"]','B','sin^2+cos^2=1. 9/25+cos^2=1. cos^2=16/25. cos=4/5.','{"A":"Same as sin","C":"Reciprocal of sin","D":"Reciprocal of cos"}','trigonometry','medium','Use sin^2+cos^2=1 to find the other ratio.'),
('a0000000-0016-0000-0000-000000000004','math','Convert 5pi/6 radians to degrees.',NULL,'["A) 120","B) 135","C) 150","D) 300"]','C','(5pi/6)(180/pi) = 900/6 = 150 degrees.','{"A":"Computed 4pi/6","B":"Computed 3pi/4","D":"Multiplied by 2 extra"}','trigonometry','medium','Radians to degrees: multiply by 180/pi.'),
('a0000000-0016-0000-0000-000000000005','math','What is the period of y=sin(2x)?',NULL,'["A) pi","B) 2pi","C) pi/2","D) 4pi"]','A','Period = 2pi/|b| = 2pi/2 = pi.','{"B":"Period of sin(x)","C":"Divided by 4","D":"Multiplied by 2"}','trigonometry','hard','Period of sin(bx) = 2pi/|b|.'),
('a0000000-0016-0000-0000-000000000006','math','In triangle ABC, a=7, b=5, and angle C=60 degrees. Find c using the law of cosines.',NULL,'["A) sqrt(39)","B) sqrt(49)","C) sqrt(74)","D) sqrt(24)"]','A','c^2=49+25-2(7)(5)cos60=74-70(0.5)=74-35=39. c=sqrt(39).','{"B":"Forgot cosine term","C":"Forgot to subtract","D":"Wrong calculation"}','trigonometry','hard','Law of cosines: c^2=a^2+b^2-2ab*cos(C).'),
-- number_properties (6 questions: 2 easy, 2 medium, 2 hard)
('a0000000-0017-0000-0000-000000000001','math','What is the greatest common factor of 12 and 18?',NULL,'["A) 3","B) 6","C) 9","D) 36"]','B','Factors of 12: 1,2,3,4,6,12. Factors of 18: 1,2,3,6,9,18. GCF=6.','{"A":"A common factor but not greatest","C":"Factor of 18 only","D":"LCM not GCF"}','number_properties','easy','GCF: largest number that divides both evenly.'),
('a0000000-0017-0000-0000-000000000002','math','Which number is both a perfect square and a factor of 36?',NULL,'["A) 6","B) 9","C) 12","D) 8"]','B','9=3^2 (perfect square) and 36/9=4 (factor of 36).','{"A":"Not a perfect square","C":"Not a perfect square","D":"Not a factor of 36"}','number_properties','easy','Perfect squares: 1, 4, 9, 16, 25, 36, 49...'),
('a0000000-0017-0000-0000-000000000003','math','What is the least common multiple of 4 and 6?',NULL,'["A) 2","B) 10","C) 12","D) 24"]','C','Multiples of 4: 4,8,12... Multiples of 6: 6,12... LCM=12.','{"A":"This is GCF","B":"Not a multiple of either","D":"A common multiple but not least"}','number_properties','medium','LCM: smallest number that both divide into evenly.'),
('a0000000-0017-0000-0000-000000000004','math','If n is an even integer, which must also be even?',NULL,'["A) n+1","B) n+3","C) n^2+1","D) n^2"]','D','Even squared is even: (2k)^2=4k^2 which is even.','{"A":"Even+odd=odd","B":"Even+odd=odd","C":"Even^2+1=odd"}','number_properties','medium','Even x even = even. Even + odd = odd.'),
('a0000000-0017-0000-0000-000000000005','math','How many prime numbers are between 20 and 40?',NULL,'["A) 3","B) 4","C) 5","D) 6"]','B','Primes: 23, 29, 31, 37. That is 4.','{"A":"Missed one","C":"Counted a composite","D":"Counted too many"}','number_properties','hard','Check each odd number for divisibility by primes up to its square root.'),
('a0000000-0017-0000-0000-000000000006','math','If the product of two consecutive integers is 72, what are they?',NULL,'["A) 7 and 8","B) 8 and 9","C) 6 and 12","D) 9 and 8"]','B','n(n+1)=72. 8x9=72.','{"A":"7x8=56","C":"Not consecutive","D":"Same as B but order matters for answer format"}','number_properties','hard','Set up: n(n+1)=72. Test integers near sqrt(72)≈8.5.'),

-- ratios_proportions (6 questions: 2 easy, 2 medium, 2 hard)
('a0000000-0018-0000-0000-000000000001','math','If the ratio of boys to girls is 3:5 and there are 15 girls, how many boys?',NULL,'["A) 6","B) 9","C) 12","D) 25"]','B','3/5 = x/15. x = 9.','{"A":"Divided 15 by 3 wrong","C":"Multiplied 3 by 4","D":"Added 15 and 10"}','ratios_proportions','easy','Set up proportion: 3/5 = x/15. Cross multiply.'),
('a0000000-0018-0000-0000-000000000002','math','A car travels 180 miles in 3 hours. What is its speed?',NULL,'["A) 45 mph","B) 55 mph","C) 60 mph","D) 90 mph"]','C','Speed=distance/time=180/3=60 mph.','{"A":"Divided by 4","B":"Wrong calculation","D":"Divided by 2"}','ratios_proportions','easy','Rate = Distance / Time.'),
('a0000000-0018-0000-0000-000000000003','math','If a shirt costs $40 and is 25% off, what is the sale price?',NULL,'["A) $10","B) $15","C) $25","D) $30"]','D','25% of 40 = $10 discount. Price = 40-10 = $30.','{"A":"Calculated discount only","B":"Wrong percentage","C":"Wrong calculation"}','ratios_proportions','medium','Sale price = original - (original x discount rate).'),
('a0000000-0018-0000-0000-000000000004','math','A map scale is 1 inch = 50 miles. Two cities are 3.5 inches apart on the map. What is the actual distance?',NULL,'["A) 150 miles","B) 175 miles","C) 200 miles","D) 350 miles"]','B','3.5 x 50 = 175 miles.','{"A":"Used 3 inches","C":"Used 4 inches","D":"Multiplied by 100"}','ratios_proportions','medium','Multiply map distance by scale factor.'),
('a0000000-0018-0000-0000-000000000005','math','A solution is 40% acid. How many mL of acid are in 250 mL of solution?',NULL,'["A) 80","B) 100","C) 40","D) 160"]','B','0.40 x 250 = 100 mL.','{"A":"Used 0.32","C":"Confused percent with mL","D":"Used 0.64"}','ratios_proportions','hard','Amount = percentage (as decimal) x total.'),
('a0000000-0018-0000-0000-000000000006','math','Working alone, Pump A fills a tank in 6 hours and Pump B in 4 hours. How long together?',NULL,'["A) 2 hours","B) 2.4 hours","C) 5 hours","D) 10 hours"]','B','Combined rate: 1/6+1/4=2/12+3/12=5/12. Time=12/5=2.4 hours.','{"A":"Divided difference","C":"Subtracted rates","D":"Added times directly"}','ratios_proportions','hard','Work problems: add rates (1/time), then invert for total time.'),
-- functions (6 questions: 2 easy, 2 medium, 2 hard)
('a0000000-0019-0000-0000-000000000001','math','If f(x)=3x+2, what is f(4)?',NULL,'["A) 12","B) 14","C) 10","D) 9"]','B','f(4)=3(4)+2=12+2=14.','{"A":"Forgot to add 2","C":"Used 3+2+4","D":"Used 3+4+2 wrong"}','functions','easy','Substitute the value for x and compute.'),
('a0000000-0019-0000-0000-000000000002','math','What is the domain of f(x)=1/(x-3)?',NULL,'["A) All real numbers","B) All real numbers except 3","C) x>3","D) x<3"]','B','Denominator cannot be zero: x-3≠0, so x≠3.','{"A":"Division by zero undefined at x=3","C":"Negative x values are valid","D":"x>3 is also valid"}','functions','easy','Domain excludes values that make denominator zero.'),
('a0000000-0019-0000-0000-000000000003','math','If f(x)=x^2-1, what is f(x+1)?',NULL,'["A) x^2+2x","B) x^2","C) x^2+2x+1","D) x^2-2"]','A','f(x+1)=(x+1)^2-1=x^2+2x+1-1=x^2+2x.','{"B":"Forgot the 2x term","C":"Forgot to subtract 1","D":"Wrong substitution"}','functions','medium','Replace every x in the formula with (x+1).'),
('a0000000-0019-0000-0000-000000000004','math','If f(x)=2x and g(x)=x+5, what is (f*g)(3)?',NULL,'["A) 48","B) 11","C) 16","D) 6"]','A','f(3)=6, g(3)=8. (f*g)(3)=f(3)*g(3)=6*8=48.','{"B":"Added f(3)+g(3)","C":"Computed f(g(3))","D":"Only computed f(3)"}','functions','medium','(f*g)(x) = f(x) * g(x). Evaluate each then multiply.'),
('a0000000-0019-0000-0000-000000000005','math','What is the inverse of f(x)=2x-6?',NULL,'["A) f^(-1)(x)=(x+6)/2","B) f^(-1)(x)=x/2+6","C) f^(-1)(x)=2x+6","D) f^(-1)(x)=(x-6)/2"]','A','y=2x-6. Swap: x=2y-6. Solve: x+6=2y, y=(x+6)/2.','{"B":"Added 6 after dividing","C":"Changed sign only","D":"Subtracted instead of adding"}','functions','hard','To find inverse: swap x and y, then solve for y.'),
('a0000000-0019-0000-0000-000000000006','math','Which describes the transformation from f(x) to f(x-3)+2?',NULL,'["A) Left 3, up 2","B) Right 3, up 2","C) Right 3, down 2","D) Left 3, down 2"]','B','x-3 shifts right 3. +2 shifts up 2.','{"A":"x-3 shifts right not left","C":"+2 shifts up not down","D":"Both wrong directions"}','functions','hard','f(x-h)+k: right h, up k. f(x+h)-k: left h, down k.'),

-- statistics_probability (6 questions: 2 easy, 2 medium, 2 hard)
('a0000000-0020-0000-0000-000000000001','math','What is the median of: 3, 7, 9, 12, 15?',NULL,'["A) 7","B) 9","C) 9.2","D) 12"]','B','Already ordered; middle value (3rd of 5) is 9.','{"A":"First quartile","C":"This is the mean","D":"Above median"}','statistics_probability','easy','Median: middle value when data is ordered. For odd n, it is position (n+1)/2.'),
('a0000000-0020-0000-0000-000000000002','math','A bag has 4 red, 3 blue, 5 green marbles. P(blue)?',NULL,'["A) 1/4","B) 3/12","C) 3/7","D) 1/3"]','A','Total=12. P(blue)=3/12=1/4.','{"B":"Correct but unsimplified","C":"Excluded green from total","D":"Divided by number of colors"}','statistics_probability','easy','P(event) = favorable / total outcomes. Simplify.'),
('a0000000-0020-0000-0000-000000000003','math','P(rolling sum of 7 with two dice)?',NULL,'["A) 1/6","B) 1/12","C) 7/36","D) 1/36"]','A','Combos summing to 7: (1,6)(2,5)(3,4)(4,3)(5,2)(6,1)=6. P=6/36=1/6.','{"B":"Counted only 3","C":"Put 7 in numerator","D":"Only 1 combo counted"}','statistics_probability','medium','List favorable outcomes systematically. Two dice = 36 total.'),
('a0000000-0020-0000-0000-000000000004','math','The mean of 5 numbers is 20. If one number is removed and the mean becomes 18, what was removed?',NULL,'["A) 22","B) 24","C) 28","D) 30"]','C','Sum=5x20=100. New sum=4x18=72. Removed=100-72=28.','{"A":"Wrong subtraction","B":"Close but wrong","D":"Used wrong mean"}','statistics_probability','medium','Total = mean x count. Find difference in totals.'),
('a0000000-0020-0000-0000-000000000005','math','In how many ways can 5 books be arranged on a shelf?',NULL,'["A) 25","B) 60","C) 120","D) 720"]','C','5! = 5x4x3x2x1 = 120.','{"A":"5^2","B":"5x4x3","D":"6!"}','statistics_probability','hard','Arrangements of n distinct items = n! (factorial).'),
('a0000000-0020-0000-0000-000000000006','math','Two events A and B are independent. P(A)=0.3, P(B)=0.5. What is P(A and B)?',NULL,'["A) 0.15","B) 0.80","C) 0.8","D) 0.2"]','A','For independent events: P(A and B)=P(A)*P(B)=0.3*0.5=0.15.','{"B":"Added probabilities","C":"Added probabilities","D":"Subtracted"}','statistics_probability','hard','Independent events: P(A and B) = P(A) x P(B).'),

-- ═══════════════════════════════════════════════════════════════════════════════
-- READING QUESTIONS (40 total)
-- ═══════════════════════════════════════════════════════════════════════════════

-- main_idea (4 questions)
('a0000000-0021-0000-0000-000000000001','reading','The main purpose of this passage is to:','Coral reefs support roughly 25% of all marine species despite covering less than 1% of the ocean floor. Rising ocean temperatures cause coral bleaching, threatening this biodiversity. Scientists are now developing heat-resistant coral strains to combat this crisis.','["A) argue against ocean conservation","B) explain threats to coral reefs and potential solutions","C) describe the history of coral research","D) compare coral reefs to rainforests"]','B','The passage identifies a threat (bleaching) and a solution (heat-resistant strains).','{"A":"The passage supports conservation","C":"No history discussed","D":"No comparison made"}','main_idea','easy','Ask: what is the passage mainly about? Eliminate too-broad or too-narrow answers.'),
('a0000000-0021-0000-0000-000000000002','reading','Which best states the central idea?','The invention of the printing press in 1440 democratized knowledge by making books affordable. Before Gutenberg, a single book could cost as much as a house. Within decades, literacy rates began climbing across Europe.','["A) Gutenberg was a genius inventor","B) Books were expensive before the printing press","C) The printing press made knowledge accessible to more people","D) Europe had low literacy rates"]','C','The passage traces how the press made books affordable, increasing access to knowledge.','{"A":"Too focused on the person","B":"Supporting detail not main idea","D":"A detail not the central point"}','main_idea','medium','The central idea encompasses all the details, not just one.'),
('a0000000-0021-0000-0000-000000000003','reading','Which title best captures the passage?','Microplastics have been found in Arctic ice, deep-sea trenches, and human blood. These tiny fragments come from degrading larger plastics and synthetic clothing fibers. Their health effects remain largely unknown, but preliminary research suggests inflammation and cellular damage.','["A) The History of Plastic Manufacturing","B) Microplastics: A Pervasive and Poorly Understood Threat","C) How to Reduce Plastic Use","D) Ocean Pollution Statistics"]','B','The passage covers ubiquity (pervasive) and unknown effects (poorly understood threat).','{"A":"Manufacturing not discussed","C":"No solutions presented","D":"Not limited to oceans"}','main_idea','medium','A good title summarizes both the topic and the angle.'),
('a0000000-0021-0000-0000-000000000004','reading','The passage primarily serves to:','Scientists long believed the brain stopped producing neurons in adulthood. However, a landmark 1998 study proved neurogenesis occurs in the hippocampus throughout life. This discovery revolutionized treatments for neurodegenerative diseases and challenged fundamental assumptions about brain plasticity.','["A) describe a scientific discovery that overturned prior beliefs","B) argue that brain research is underfunded","C) compare old and new brain imaging techniques","D) explain how neurons function"]','A','The passage describes a discovery (neurogenesis) that contradicted previous beliefs.','{"B":"Funding not discussed","C":"Imaging not discussed","D":"Neuron function not the focus"}','main_idea','hard','Identify what the passage does: describes, argues, compares, or explains.'),

-- detail_identification (4 questions)
('a0000000-0022-0000-0000-000000000001','reading','According to the passage, what determines direction in the waggle dance?','Honeybees perform a waggle dance to communicate food location. The angle relative to vertical indicates direction relative to the sun. The duration of the waggle phase indicates distance.','["A) speed of dance","B) duration of waggle","C) angle relative to vertical","D) number of repetitions"]','C','The passage states: angle relative to vertical indicates direction.','{"A":"Speed not mentioned","B":"Duration = distance","D":"Repetitions not mentioned"}','detail_identification','easy','For detail questions, find the exact sentence that answers it.'),
('a0000000-0022-0000-0000-000000000002','reading','According to the passage, what is the primary advantage of the new material?','Researchers developed transparent wood stronger than glass with better insulation. Made by removing lignin and infusing with epoxy, it could replace windows, reducing heating costs by 30%.','["A) Cheaper to make","B) Better insulation","C) Completely transparent","D) Eliminates heating"]','B','Passage emphasizes better insulation and 30% heating reduction as primary advantage.','{"A":"Cost not mentioned","C":"A feature but not the main advantage discussed","D":"Reduces by 30% not eliminates"}','detail_identification','easy','Distinguish between features mentioned and the primary advantage emphasized.'),
('a0000000-0022-0000-0000-000000000003','reading','The passage states that vertical farming uses how much less water?','Vertical farming uses 95% less water than traditional agriculture and eliminates pesticide need. Crops grow year-round in controlled indoor environments unaffected by weather.','["A) 50%","B) 75%","C) 95%","D) 100%"]','C','Directly stated: uses 95% less water.','{"A":"Not stated","B":"Not stated","D":"Still uses some water"}','detail_identification','medium','Look for exact numbers and percentages stated in the text.'),
('a0000000-0022-0000-0000-000000000004','reading','Based on the passage, which year did life expectancy reach 77?','In 1900, American life expectancy was 47. By 1950 it reached 68. By 2020 it reached 77. Gains were largest in the first half of the century.','["A) 1900","B) 1950","C) 2000","D) 2020"]','D','The passage states: by 2020, it reached 77.','{"A":"47 in 1900","B":"68 in 1950","C":"Year not mentioned"}','detail_identification','hard','Match specific numbers to their associated dates or contexts.'),
-- inference (4 questions)
('a0000000-0023-0000-0000-000000000001','reading','The passage implies that traditional farming:','Vertical farming uses 95% less water and eliminates pesticides. Crops grow year-round unaffected by weather in controlled environments.','["A) is completely obsolete","B) uses more water and pesticides","C) is less expensive","D) produces lower quality crops"]','B','By saying vertical uses 95% less water and eliminates pesticides, it implies traditional uses more.','{"A":"Not stated as obsolete","C":"Implied by high energy costs but not the strongest inference","D":"Quality not discussed"}','inference','easy','Inferences must be directly supported by passage evidence.'),
('a0000000-0023-0000-0000-000000000002','reading','It can be inferred that the author believes:','Public libraries serve as community centers offering free internet, job training, and children''s programs. In an era of digital divide, libraries remain committed to equitable access.','["A) Libraries should only lend books","B) Libraries play a vital community equity role","C) Digital resources make libraries obsolete","D) Libraries should charge fees"]','B','Author emphasizes equity and broader services, clearly valuing libraries'' expanded role.','{"A":"Author says they are more than books","C":"Author says they combat digital divide","D":"Author emphasizes free access"}','inference','medium','Author''s beliefs are shown through what they emphasize and praise.'),
('a0000000-0023-0000-0000-000000000003','reading','The passage suggests that automation:','Automation is a double-edged sword. It increases efficiency and reduces error while displacing workers lacking technical skills.','["A) is dangerous to operate","B) has both benefits and drawbacks","C) will eventually fail","D) only works in manufacturing"]','B','Double-edged sword means both advantages and disadvantages.','{"A":"Physical danger not discussed","C":"Failure not predicted","D":"No industry limitation stated"}','inference','medium','Figurative language (double-edged sword) often contains implied meaning.'),
('a0000000-0023-0000-0000-000000000004','reading','Based on the data, it can be inferred that:','Electric vehicles produce zero direct emissions. However, environmental benefits depend on electricity generation. In coal-heavy regions, an EV''s carbon footprint may be only marginally better.','["A) EVs are always better for environment","B) EVs environmental benefit varies by region","C) Coal power is being eliminated","D) Gasoline cars are more efficient"]','B','The passage says benefits depend on how electricity is generated, implying regional variation.','{"A":"Passage qualifies this with however","C":"Not stated","D":"Not stated"}','inference','hard','Look for qualifying language (however, depends on) that limits generalizations.'),

-- vocabulary_in_context (4 questions)
('a0000000-0024-0000-0000-000000000001','reading','In context, abstract most nearly means:','Bees perform a waggle dance representing real-world locations through symbolic movement, demonstrating abstract communication.','["A) difficult to observe","B) representational or symbolic","C) random","D) limited"]','B','The passage defines abstract as representing real-world things through symbols.','{"A":"Dance is observable","C":"Dance is systematic","D":"Not suggested"}','vocabulary_in_context','easy','Look for context clues—definitions or examples often follow the word.'),
('a0000000-0024-0000-0000-000000000002','reading','The word unprecedented most nearly means:','The pace of change during the Industrial Revolution was unprecedented, transforming society in ways never before experienced.','["A) slow","B) expected","C) without prior example","D) temporary"]','C','Unprecedented = without precedent = never before experienced, as context confirms.','{"A":"Opposite of the context","B":"Opposite meaning","D":"No suggestion of temporariness"}','vocabulary_in_context','medium','Unprecedented literally means without precedent—no prior example.'),
('a0000000-0024-0000-0000-000000000003','reading','As used in the passage, pervasive means:','Microplastics are pervasive—found in Arctic ice, deep-sea trenches, and even human blood, demonstrating their presence everywhere.','["A) harmful","B) widespread everywhere","C) invisible","D) temporary"]','B','Context shows microplastics are everywhere (Arctic, deep sea, blood) = widespread.','{"A":"Harm is discussed separately","C":"They are detectable","D":"They persist in the environment"}','vocabulary_in_context','medium','Use the examples given to determine the word''s meaning in context.'),
('a0000000-0024-0000-0000-000000000004','reading','The word revolutionized most nearly means:','The discovery of adult neurogenesis revolutionized treatment approaches, fundamentally changing how scientists think about brain repair.','["A) slightly improved","B) completely transformed","C) complicated","D) delayed"]','B','Revolutionized paired with fundamentally changing indicates complete transformation.','{"A":"Too mild for revolutionized","C":"Not about complexity","D":"Opposite direction"}','vocabulary_in_context','hard','Revolutionized implies radical, complete change—not minor improvement.'),

-- author_purpose (4 questions)
('a0000000-0025-0000-0000-000000000001','reading','The author''s primary purpose is to:','A 2024 study found neighborhoods with community gardens saw 15% higher satisfaction and 20% lower crime rates. Gardens also provide fresh produce in food deserts.','["A) entertain readers with garden stories","B) persuade readers to start gardening","C) inform readers about community garden benefits","D) compare different types of gardens"]','C','The passage presents data about benefits without arguing readers should garden.','{"A":"Informational not entertaining","B":"Presents data, doesn''t directly persuade","D":"No comparison made"}','author_purpose','easy','Purpose: inform (facts), persuade (argument), entertain (story), describe (imagery).'),
('a0000000-0025-0000-0000-000000000002','reading','The passage most likely appeared in:','Methods: Participants (n=240) were randomly assigned to intervention or control groups. The intervention group received 8 weeks of mindfulness training. Results analyzed using two-sample t-test.','["A) personal blog","B) scientific research paper","C) self-help book","D) news article"]','B','Scientific methodology language: random assignment, control groups, statistical analysis.','{"A":"Too formal","C":"No methodology sections in self-help","D":"Too technical for news"}','author_purpose','medium','Identify genre from language, structure, and technical level.'),
('a0000000-0025-0000-0000-000000000003','reading','The author develops the argument primarily through:','The monarch butterfly navigates 3,000 miles using an internal compass. The Arctic tern completes 44,000-mile migrations. Even dung beetles orient using the Milky Way. Navigation is fundamental biology.','["A) statistical data","B) personal anecdotes","C) specific examples from nature","D) expert quotes"]','C','Three animal examples build toward the concluding argument.','{"A":"Numbers support examples but aren''t the primary method","B":"Facts not personal stories","D":"No experts quoted"}','author_purpose','medium','Identify HOW the author builds their case: examples, data, quotes, or logic.'),
('a0000000-0025-0000-0000-000000000004','reading','The author''s tone toward the city council is best described as:','The council''s decision to cut arts funding by 60% reveals a staggering lack of vision. Study after study confirms arts education improves performance, yet leaders sacrifice growth for savings.','["A) neutral","B) critical and passionate","C) humorous","D) uncertain"]','B','Words like staggering lack of vision and sacrifice show strong criticism.','{"A":"Language is clearly opinionated","C":"No humor present","D":"Author is confident in position"}','author_purpose','hard','Strong emotional words signal opinion; neutral words signal objectivity.'),
-- tone_attitude (4 questions)
('a0000000-0026-0000-0000-000000000001','reading','The author''s attitude toward the subject is best described as:','The new community center will provide essential services including childcare, tutoring, and health screenings. Construction begins next month.','["A) critical and skeptical","B) enthusiastic and supportive","C) objective and informational","D) sarcastic"]','C','Factual reporting without emotional language indicates objectivity.','{"A":"No criticism present","B":"No enthusiasm expressed","D":"No sarcasm"}','tone_attitude','easy','Identify emotional language vs. neutral reporting to determine tone.'),
('a0000000-0026-0000-0000-000000000002','reading','The narrator''s tone shifts from _____ to _____ in this passage:','At first I dreaded the assignment—another tedious group project. But as we worked together, I discovered my teammates brought creativity I never expected. By the end, I was grateful for the collaboration.','["A) excitement to boredom","B) reluctance to appreciation","C) anger to sadness","D) confidence to doubt"]','B','Dreaded/tedious shows reluctance; grateful shows appreciation. Clear shift.','{"A":"Starts negative not excited","C":"No anger or sadness","D":"Starts with dread not confidence"}','tone_attitude','medium','Track emotional words through the passage to identify shifts.'),
('a0000000-0026-0000-0000-000000000003','reading','The author''s use of quotation marks around "progress" suggests:','The city''s "progress" has displaced thousands of long-term residents and destroyed historic neighborhoods in favor of luxury developments.','["A) direct quotation from an official","B) skepticism about whether it truly is progress","C) emphasis on the word","D) a technical definition"]','B','Scare quotes around progress signal the author questions whether it deserves that label.','{"A":"No speaker attributed","C":"Italics are for emphasis","D":"No definition follows"}','tone_attitude','medium','Scare quotes indicate the author doubts or disputes the term.'),
('a0000000-0026-0000-0000-000000000004','reading','The passage''s overall tone is best described as:','While some herald artificial intelligence as humanity''s greatest achievement, one must consider the millions of jobs already eliminated and ask whether our relentless pursuit of efficiency has come at too great a human cost.','["A) celebratory","B) indifferent","C) cautionary and reflective","D) hostile"]','C','Acknowledges positives but raises concerns (too great a cost) = cautionary and reflective.','{"A":"Questions the celebration","B":"Clearly engaged with the topic","D":"Measured not hostile"}','tone_attitude','hard','Cautionary tone: acknowledges both sides but emphasizes risks.'),

-- cause_effect (4 questions)
('a0000000-0027-0000-0000-000000000001','reading','According to the passage, what causes coral bleaching?','Rising ocean temperatures stress coral, causing them to expel the algae that give them color. Without these algae, coral turns white—a process called bleaching—and eventually dies.','["A) pollution","B) rising ocean temperatures","C) overfishing","D) strong currents"]','B','Directly stated: rising temperatures cause corals to expel algae (bleaching).','{"A":"Not mentioned as cause","C":"Not mentioned","D":"Not mentioned"}','cause_effect','easy','Find the stated cause-effect relationship in the passage.'),
('a0000000-0027-0000-0000-000000000002','reading','What effect did the printing press have according to the passage?','The printing press made books affordable for the first time. Before Gutenberg, books cost as much as houses. Within decades of the press, literacy rates began climbing across Europe.','["A) Increased book prices","B) Decreased literacy","C) Increased literacy rates","D) Caused paper shortages"]','C','Affordable books led to climbing literacy rates (stated effect).','{"A":"Opposite—prices decreased","B":"Opposite—literacy increased","D":"Not mentioned"}','cause_effect','easy','Trace the chain: press → affordable books → increased literacy.'),
('a0000000-0027-0000-0000-000000000003','reading','Based on the passage, heavy social media use leads to:','Research shows heavy social media use correlates with increased isolation and depression. Users compare everyday lives to curated highlights, creating unrealistic expectations.','["A) improved communication","B) increased feelings of isolation","C) better time management","D) stronger friendships"]','B','Passage states correlation with increased isolation and depression.','{"A":"Opposite of findings","C":"Not discussed","D":"Opposite—isolation increases"}','cause_effect','medium','Identify what the research found as the effect of heavy use.'),
('a0000000-0027-0000-0000-000000000004','reading','The passage suggests what chain of causation?','Deforestation removes trees that absorb CO2. This increases atmospheric carbon, which traps heat, raising global temperatures. Higher temperatures then melt polar ice, raising sea levels.','["A) Ice melting causes deforestation","B) Deforestation leads to rising sea levels through a chain of effects","C) Sea levels cause carbon increases","D) Temperature drops cause ice formation"]','B','Chain: deforestation → more CO2 → higher temps → ice melt → sea level rise.','{"A":"Reverses the causation","C":"Reverses causation","D":"Opposite of what passage describes"}','cause_effect','hard','Trace multi-step causal chains: A causes B causes C.'),

-- comparison_contrast (4 questions)
('a0000000-0028-0000-0000-000000000001','reading','According to the passage, how do the two approaches differ?','Traditional classrooms use lectures where teachers present information. Flipped classrooms have students watch lectures at home and use class time for practice and discussion.','["A) Traditional is newer","B) Flipped uses class for practice while traditional uses it for lectures","C) They are identical","D) Traditional requires more technology"]','B','Clear contrast: traditional = class lectures; flipped = class practice.','{"A":"Flipped is the newer approach","C":"They differ significantly","D":"Flipped requires more technology"}','comparison_contrast','easy','Identify what is being compared and how they differ.'),
('a0000000-0028-0000-0000-000000000002','reading','The relationship between Paragraph 1 and 2 is best described as:','P1: Electric vehicles produce zero direct emissions with superior efficiency. P2: However, benefits depend on electricity generation. In coal regions, EVs may be only marginally better.','["A) Paragraph 2 contradicts 1","B) Paragraph 2 supports 1","C) Paragraph 2 qualifies claims in 1","D) They discuss unrelated topics"]','C','Paragraph 2 adds conditions/limitations without fully contradicting paragraph 1.','{"A":"Doesn''t say EVs are bad","B":"Introduces complications","D":"Directly related"}','comparison_contrast','medium','Qualifies = adds conditions or limitations without full contradiction.'),
('a0000000-0028-0000-0000-000000000003','reading','The author compares the two systems primarily to:','Democracy allows citizens to choose leaders through elections. Autocracy concentrates power in one ruler. The author notes democracies tend toward slower decision-making but greater long-term stability.','["A) argue one is always better","B) show each has different strengths and weaknesses","C) prove autocracy is superior","D) explain election processes"]','B','Author presents tradeoffs (slower but more stable) without declaring a winner.','{"A":"Author shows tradeoffs not absolutes","C":"Not argued","D":"Elections are one detail"}','comparison_contrast','medium','Look for balanced language showing tradeoffs vs. one-sided argument.'),
('a0000000-0028-0000-0000-000000000004','reading','How does the author use the contrast between ancient and modern medicine?','Ancient healers relied on observation and herbal remedies passed through generations. Modern medicine uses controlled trials and molecular biology. Yet both share the goal of alleviating suffering.','["A) To show ancient medicine was wrong","B) To argue modern is always better","C) To highlight shared purpose despite different methods","D) To suggest we abandon modern medicine"]','C','Despite contrasting methods, the author emphasizes shared purpose (alleviating suffering).','{"A":"Not judging ancient medicine","B":"Not arguing superiority","D":"Not suggested"}','comparison_contrast','hard','Contrasts can highlight similarities (shared purpose) rather than just differences.'),
-- sequence_events (4 questions)
('a0000000-0029-0000-0000-000000000001','reading','What is the correct order of steps described?','First seeds are planted in spring. After germination, seedlings need water and shade. Once six inches tall, transplant to full sun. Harvest in late summer when fruit turns red.','["A) harvest, plant, transplant, germinate","B) plant, germinate, transplant, harvest","C) transplant, plant, harvest, germinate","D) germinate, plant, harvest, transplant"]','B','Signal words: first (plant), after (germinate), once tall (transplant), harvest.','{"A":"Reversed order","C":"Wrong sequence","D":"Wrong sequence"}','sequence_events','easy','Look for signal words: first, then, after, once, finally.'),
('a0000000-0029-0000-0000-000000000002','reading','According to the passage, what happens immediately after evaporation?','Solar energy heats surface water causing evaporation. Water vapor rises, cools, and condenses into clouds. Precipitation returns water to the surface.','["A) precipitation","B) water vapor rises and cools","C) water flows to ocean","D) infiltration into groundwater"]','B','After evaporation: vapor rises, cools, condenses. Then precipitation.','{"A":"Precipitation comes after condensation","C":"Occurs after precipitation","D":"Occurs after precipitation"}','sequence_events','medium','Identify the step immediately following the one asked about.'),
('a0000000-0029-0000-0000-000000000003','reading','Which event occurred first according to the passage?','The 1998 study proved adult neurogenesis. This discovery then revolutionized treatments. Previously, scientists believed the brain stopped producing neurons.','["A) Treatments were revolutionized","B) Scientists believed brain stopped making neurons","C) The 1998 study was published","D) Neurogenesis was proven"]','B','Previously signals this belief came before the 1998 study.','{"A":"Result of the discovery","C":"Came after the prior belief","D":"Same as C"}','sequence_events','medium','Words like previously, before, after establish timeline.'),
('a0000000-0029-0000-0000-000000000004','reading','Arrange these events in chronological order based on the passage:','The telescope launched December 2021. It traveled to L2, nearly 1 million miles away. Scientists began receiving first images in mid-2022. These images revealed previously unseen galaxy formations.','["A) launch, travel, images, discoveries","B) images, launch, discoveries, travel","C) discoveries, images, travel, launch","D) travel, launch, images, discoveries"]','A','Chronological: launched, traveled to L2, received images, made discoveries.','{"B":"Images before launch is impossible","C":"Completely reversed","D":"Travel before launch is impossible"}','sequence_events','hard','Use dates and logical dependencies to establish order.'),

-- generalization (4 questions)
('a0000000-0030-0000-0000-000000000001','reading','Which generalization is best supported by the passage?','Monarch butterflies migrate 3,000 miles. Arctic terns fly 44,000 miles annually. Dung beetles navigate using the Milky Way. These examples show navigation is fundamental biology, not uniquely human.','["A) All animals can navigate long distances","B) Navigation ability exists across diverse species","C) Insects are smarter than birds","D) Only butterflies can navigate"]','B','Three diverse examples (insect, bird, beetle) support wide presence of navigation.','{"A":"Too strong—not all animals","C":"Not compared","D":"Contradicted by other examples"}','generalization','easy','Good generalizations are supported by multiple examples without overreaching.'),
('a0000000-0030-0000-0000-000000000002','reading','Which conclusion is best supported?','Life expectancy: 1900=47, 1950=68, 2020=77. Largest gains in first half driven by sanitation, vaccination, and antibiotics rather than chronic disease treatment.','["A) Technology no longer advances","B) Sanitation alone caused all gains","C) Life expectancy will keep rising equally","D) Early public health measures drove largest gains"]','D','Passage states gains were largest in first half from public health measures.','{"A":"Not stated","B":"Multiple factors listed not just sanitation","C":"Data shows gains slowing"}','generalization','medium','Conclusions must be supported by evidence—not assumptions.'),
('a0000000-0030-0000-0000-000000000003','reading','The passage best supports which broad claim?','Studies show arts education improves math scores by 12%, reading comprehension by 8%, and reduces behavioral issues by 20% across diverse school demographics.','["A) Arts education benefits only gifted students","B) Arts education provides measurable academic and behavioral benefits","C) Arts should replace math classes","D) Behavioral issues cannot be addressed"]','B','Multiple data points across demographics support broad academic and behavioral benefits.','{"A":"Contradicted by across diverse demographics","C":"Not argued","D":"Contradicted by 20% reduction"}','generalization','medium','Data across diverse groups supports broader generalizations.'),
('a0000000-0030-0000-0000-000000000004','reading','Which generalization does the author explicitly caution against?','While social media correlates with isolation in heavy users, moderate users report enhanced social connection. The relationship is complex and dose-dependent, resisting simple generalizations.','["A) Social media has no effects","B) Social media always harms mental health","C) Social media is beneficial for everyone","D) Both B and C—the author warns against absolutes"]','D','The author explicitly says it resists simple generalizations—both always harmful and always beneficial are too simple.','{"A":"Effects clearly exist","B":"Only one simplification the author warns against","C":"Only one simplification"}','generalization','hard','When authors say resists simple generalizations they warn against all absolutes.'),

-- ═══════════════════════════════════════════════════════════════════════════════
-- SCIENCE QUESTIONS (40 total)
-- ═══════════════════════════════════════════════════════════════════════════════

-- data_representation (4 questions)
('a0000000-0031-0000-0000-000000000001','science','According to Table 1, at what temperature is the reaction rate highest?','Table 1: 10C=5mL/min, 20C=12mL/min, 30C=24mL/min, 40C=35mL/min, 50C=22mL/min, 60C=8mL/min.',NULL,'["A) 30C","B) 40C","C) 50C","D) 60C"]','B','Highest rate is 35 mL/min at 40C.','{"A":"24 is not maximum","C":"Rate declining","D":"Rate very low"}','data_representation','easy','For peak/maximum questions, find the highest value in the data.'),
('a0000000-0031-0000-0000-000000000002','science','Based on the graph, plant height increases most between which weeks?','Bar graph: Week1=2cm, Week2=5cm, Week3=12cm, Week4=15cm, Week5=16cm.',NULL,'["A) Week 1-2","B) Week 2-3","C) Week 3-4","D) Week 4-5"]','B','Week 2-3: increase of 7cm (largest single-week increase).','{"A":"3cm increase","C":"3cm increase","D":"1cm increase"}','data_representation','easy','Calculate the difference between consecutive data points.'),
('a0000000-0031-0000-0000-000000000003','science','What trend does the data show?','Graph: As fertilizer concentration increases from 0 to 50 g/L, yield rises. From 50-100 g/L, yield remains constant. Above 100 g/L, yield decreases.',NULL,'["A) Yield always increases with fertilizer","B) Yield increases then plateaus then decreases","C) Yield decreases then increases","D) No relationship exists"]','B','Three phases: increase, plateau, decrease—a common biological response curve.','{"A":"Ignores plateau and decrease","C":"Opposite of initial trend","D":"Clear pattern exists"}','data_representation','medium','Describe the overall pattern including all phases of the data.'),
('a0000000-0031-0000-0000-000000000004','science','Which variable shows the strongest correlation with test scores?','Table: Sleep(hrs) r=0.72, Study(hrs) r=0.85, Exercise(hrs) r=0.31, Screen(hrs) r=-0.45.',NULL,'["A) Sleep","B) Study hours","C) Exercise","D) Screen time"]','B','r=0.85 has the largest absolute value, indicating strongest correlation.','{"A":"r=0.72 is strong but not strongest","C":"r=0.31 is weak","D":"r=-0.45 is moderate negative"}','data_representation','hard','Correlation strength is determined by absolute value of r, not sign.'),

-- research_summaries (4 questions)
('a0000000-0032-0000-0000-000000000001','science','What was the purpose of Study 1?','Study 1: Researchers measured reaction times of 50 subjects after 0, 100, and 200mg caffeine. Study 2: Researchers measured sleep quality of the same subjects that night.',NULL,'["A) To measure sleep quality","B) To test caffeine''s effect on reaction time","C) To compare coffee brands","D) To measure heart rate"]','B','Study 1 specifically measured reaction times with varying caffeine doses.','{"A":"That was Study 2","C":"Brands not compared","D":"Heart rate not measured"}','research_summaries','easy','Match the purpose to what was actually measured in each study.'),
('a0000000-0032-0000-0000-000000000002','science','How did Study 2 build on Study 1?','Study 1 found caffeine improved reaction time at all doses. Study 2 examined whether the same doses affected sleep quality that night.','["A) It contradicted Study 1","B) It examined a different effect of the same variable","C) It used different subjects","D) It tested a different substance"]','B','Same variable (caffeine), same subjects, but measured a different outcome (sleep vs reaction time).','{"A":"Doesn''t contradict","C":"Same subjects stated","D":"Same substance"}','research_summaries','medium','Studies often build by examining different effects of the same treatment.'),
('a0000000-0032-0000-0000-000000000003','science','Which criticism most weakens the study?','Study: 10 college students drank energy drinks for 1 week. Researchers found 80% reported better focus. Conclusion: energy drinks improve cognitive function.','["A) The study should have used rats","B) Small sample of one demographic with no control group and self-reported data","C) The study lasted too long","D) Energy drinks are popular"]','B','Multiple flaws: tiny sample (10), one demographic (college), no control, self-reported.','{"A":"Human subjects appropriate","C":"One week is very short","D":"Popularity irrelevant to methodology"}','research_summaries','medium','Evaluate sample size, diversity, controls, and measurement objectivity.'),
('a0000000-0032-0000-0000-000000000004','science','Which conclusion is supported by BOTH studies?','Study 1: Antibiotic X killed 95% bacteria at 10μg/mL. Study 2: Antibiotic X was effective against drug-resistant strains at 15μg/mL, while Y required 100μg/mL.','["A) X is ineffective","B) X is more potent than Y across multiple bacterial types","C) Y should never be used","D) Both antibiotics are identical"]','B','Both studies show X effective at low concentrations against regular and resistant strains.','{"A":"Contradicted by data","C":"Y still works at higher doses","D":"Different potencies shown"}','research_summaries','hard','Conclusions from multiple studies must be supported by data from both.'),

-- conflicting_viewpoints (4 questions)
('a0000000-0033-0000-0000-000000000001','science','On what point do Scientists 1 and 2 agree?','Scientist 1: Dinosaurs went extinct from an asteroid impact. Scientist 2: Volcanic activity caused extinction. Both note the event occurred approximately 66 million years ago.','["A) The cause of extinction","B) The timing of extinction","C) The role of asteroids","D) The role of volcanoes"]','B','Both agree it was 66 million years ago; they disagree on cause.','{"A":"They disagree on cause","C":"Only Scientist 1 supports this","D":"Only Scientist 2 supports this"}','conflicting_viewpoints','easy','Find common ground between opposing viewpoints.'),
('a0000000-0033-0000-0000-000000000002','science','Which evidence would support Scientist 2 over Scientist 1?','Scientist 1: Mass extinction from sudden asteroid impact. Scientist 2: Gradual extinction from sustained volcanic activity over thousands of years.','["A) Fossil record showing sudden disappearance","B) Fossil record showing gradual decline over 100,000 years","C) Finding an impact crater","D) Evidence of a single catastrophic event"]','B','Gradual decline supports sustained volcanic activity (Scientist 2) over sudden impact (Scientist 1).','{"A":"Supports sudden impact—Scientist 1","C":"Supports Scientist 1","D":"Supports Scientist 1"}','conflicting_viewpoints','medium','Match evidence to which hypothesis it specifically supports.'),
('a0000000-0033-0000-0000-000000000003','science','What is the fundamental disagreement?','Model A: Climate change is primarily driven by CO2 emissions from human activity since industrialization. Model B: Climate change is primarily driven by natural solar cycles occurring over millennia.','["A) Whether climate is changing","B) The primary driver of climate change","C) Whether CO2 exists","D) Whether the sun exists"]','B','Both acknowledge change; they disagree on whether humans or solar cycles are the primary cause.','{"A":"Both agree it is changing","C":"Both acknowledge CO2","D":"Both acknowledge the sun"}','conflicting_viewpoints','medium','Identify the specific point of disagreement, not areas of agreement.'),
('a0000000-0033-0000-0000-000000000004','science','Which new finding would reconcile both viewpoints?','Hypothesis A: Exercise benefits come from cardiovascular improvement. Hypothesis B: Benefits come from neurochemical changes (endorphins, serotonin).','["A) Exercise has no benefits","B) Exercise simultaneously improves cardiovascular and neurochemical systems","C) Only diet matters","D) Neither cardiovascular nor neurochemical changes occur"]','B','Finding that both mechanisms operate simultaneously would reconcile the viewpoints.','{"A":"Contradicts both","C":"Irrelevant","D":"Contradicts both"}','conflicting_viewpoints','hard','Reconciliation often shows both mechanisms are valid simultaneously.'),

-- interpreting_graphs (4 questions)
('a0000000-0034-0000-0000-000000000001','science','Based on the graph, what relationship exists between pressure and volume?','As pressure increases 1-5 atm, volume decreases 10L to 2L in a hyperbolic curve.',NULL,'["A) directly proportional","B) inversely proportional","C) no relationship","D) exponentially increasing"]','B','As one increases, the other decreases = inverse relationship.','{"A":"They move opposite directions","C":"Clear mathematical relationship","D":"Volume decreases"}','interpreting_graphs','easy','If one goes up while other goes down: inverse. Both go up: direct.'),
('a0000000-0034-0000-0000-000000000002','science','At what point does the population growth rate change?','Graph shows bacterial population: exponential growth days 0-3, plateau days 3-5, decline days 5-7.',NULL,'["A) Day 0","B) Day 3","C) Day 5","D) Day 7"]','B','Growth changes from exponential to plateau at day 3 (inflection point).','{"A":"Growth just starting","C":"Changes from plateau to decline","D":"End of observation"}','interpreting_graphs','medium','Inflection points occur where the curve''s direction or rate changes.'),
('a0000000-0034-0000-0000-000000000003','science','What can be predicted for day 8 based on the trend?','Population: Day5=1000, Day6=800, Day7=640. The decline rate appears consistent at about 20% per day.',NULL,'["A) 0","B) 512","C) 640","D) 1000"]','B','20% decline: 640 × 0.8 = 512.','{"A":"Too extreme","C":"No decline predicted","D":"Growth predicted"}','interpreting_graphs','medium','Extrapolate by applying the observed rate to the next time point.'),
('a0000000-0034-0000-0000-000000000004','science','Which graph feature indicates equilibrium?','A graph shows concentration of reactants decreasing and products increasing until both lines become flat and horizontal at time=10min.',NULL,'["A) Where lines cross","B) Where both lines become horizontal","C) The steepest part of the curve","D) The starting point"]','B','Equilibrium = no net change = both concentrations constant = horizontal lines.','{"A":"Crossing shows equal concentration, not necessarily equilibrium","C":"Steepest = fastest change, not equilibrium","D":"Starting point is pre-reaction"}','interpreting_graphs','hard','Equilibrium on a graph: concentrations stop changing (horizontal lines).'),
-- experimental_design (4 questions)
('a0000000-0035-0000-0000-000000000001','science','What is the control group?','To test caffeine on reaction time: Group 1 got 200mg caffeine, Group 2 got 100mg, Group 3 got a sugar pill. All completed reaction tests.',NULL,'["A) Group 1","B) Group 2","C) Group 3","D) No control exists"]','C','Group 3 receives placebo (no caffeine) = control for baseline comparison.','{"A":"Experimental group highest dose","B":"Experimental group moderate dose","D":"Group 3 is the control"}','experimental_design','easy','Control group: receives no treatment or placebo for baseline comparison.'),
('a0000000-0035-0000-0000-000000000002','science','Which is the dependent variable?','Scientists varied fertilizer concentration (0-15g/L) on tomato plants and measured fruit count after 8 weeks. Soil, sunlight, and water were constant.',NULL,'["A) Fertilizer concentration","B) Number of fruits","C) Soil type","D) Sunlight"]','B','Dependent variable is what you measure (fruit count). Independent is what you change (fertilizer).','{"A":"Independent variable","C":"Controlled variable","D":"Controlled variable"}','experimental_design','easy','Independent = changed. Dependent = measured. Controlled = kept constant.'),
('a0000000-0035-0000-0000-000000000003','science','Which setup best tests if music affects plant growth?',NULL,NULL,'["A) Play music to one plant for a week","B) Play music to 20 plants, no music to 20 identical plants, measure weekly for 8 weeks","C) Play different genres to one plant daily","D) Survey gardeners about music and plants"]','B','Large sample, control group, single variable, extended time = proper design.','{"A":"No control, one subject","C":"No control, changes variable daily","D":"Not an experiment"}','experimental_design','medium','Good experiments: large sample, control group, one variable, all else constant.'),
('a0000000-0035-0000-0000-000000000004','science','Which change would most improve this experiment?','A student tested whether temperature affects enzyme activity using one trial at each temperature (20C, 30C, 40C, 50C).','["A) Use more temperatures","B) Perform multiple trials at each temperature","C) Change the enzyme","D) Remove the 50C trial"]','B','Multiple trials improve reliability by reducing impact of random error.','{"A":"More data points help but replication is more important","C":"Changes the experiment","D":"Removes data"}','experimental_design','hard','Replication (multiple trials) is essential for reliable results.'),

-- variable_relationships (4 questions)
('a0000000-0036-0000-0000-000000000001','science','Which variable has the greatest effect on plant growth?','Group A (full light, daily water): 32cm. Group B (full light, weekly water): 28cm. Group C (low light, daily water): 14cm. Group D (low light, weekly water): 12cm.',NULL,'["A) Water frequency","B) Light exposure","C) Soil type","D) Temperature"]','B','Light change: 32 vs 14 = 18cm diff. Water change: 32 vs 28 = 4cm diff. Light has greater effect.','{"A":"Only 2-4cm difference","C":"Not varied","D":"Not varied"}','variable_relationships','easy','Compare groups differing in only one variable to isolate each factor.'),
('a0000000-0036-0000-0000-000000000002','science','What relationship exists between enzyme activity and pH?','Activity at pH 2=10%, pH 4=40%, pH 6=80%, pH 7=100%, pH 8=75%, pH 10=20%, pH 12=5%.',NULL,'["A) Activity always increases with pH","B) Activity peaks at pH 7 and decreases on both sides","C) pH has no effect","D) Activity is constant across pH"]','B','Bell-shaped curve peaking at pH 7 (optimal pH).','{"A":"Decreases after pH 7","C":"Clear relationship exists","D":"Values vary significantly"}','variable_relationships','medium','Enzymes have optimal conditions; activity decreases above and below optimum.'),
('a0000000-0036-0000-0000-000000000003','science','If both temperature AND concentration are doubled, what happens to reaction rate based on the data?','Data shows: doubling temperature doubles rate; doubling concentration increases rate 1.5x.',NULL,'["A) Rate doubles","B) Rate triples","C) Rate increases by factor of 3","D) Rate increases by factor of 2 x 1.5 = 3"]','C','Combined: 2 × 1.5 = 3x the original rate.','{"A":"Only accounts for temperature","B":"Same as C (3x)","D":"Same answer as C written differently"}','variable_relationships','hard','When independent variables combine, multiply their individual effects.'),
('a0000000-0036-0000-0000-000000000004','science','Based on the data, which factor is most likely a confounding variable?','Study: students who ate breakfast scored higher on tests. However, breakfast-eaters also slept more, exercised regularly, and had higher family income.',NULL,'["A) Test difficulty","B) Family income and lifestyle factors","C) Time of day","D) Teacher quality"]','B','Multiple correlated factors (sleep, exercise, income) could explain the result instead of breakfast alone.','{"A":"Not mentioned as varying","C":"Not mentioned","D":"Not mentioned as varying"}','variable_relationships','hard','Confounding variables correlate with both the independent and dependent variables.'),

-- hypothesis_evaluation (4 questions)
('a0000000-0037-0000-0000-000000000001','science','Which hypothesis is best supported by the fossil evidence?','Oldest layer: marine only. Next: marine + early land plants. Next: land plants + insects + amphibians. Newest: diverse mammals.',NULL,'["A) Life started on land","B) Life originated in water and moved to land over time","C) All species appeared at once","D) Mammals evolved before amphibians"]','B','Progressive appearance of land life in newer layers supports water-to-land evolution.','{"A":"Oldest = marine only","C":"Sequential appearance","D":"Amphibians appear in older layer"}','hypothesis_evaluation','easy','Match the hypothesis to the pattern in the data.'),
('a0000000-0037-0000-0000-000000000002','science','Which observation would DISPROVE the hypothesis?','Hypothesis: All metals expand when heated.',NULL,'["A) Iron expands when heated","B) A metal contracts when heated","C) Water expands when heated","D) Plastic expands when heated"]','B','A single metal contracting when heated disproves the ALL metals claim.','{"A":"Supports the hypothesis","C":"Water is not a metal","D":"Plastic is not a metal"}','hypothesis_evaluation','medium','To disprove an ALL statement, you need one counterexample.'),
('a0000000-0037-0000-0000-000000000003','science','Which experiment would best test the hypothesis: Plants grow faster in blue light than red light?',NULL,NULL,'["A) Grow plants in blue light only","B) Grow identical plants in blue vs red vs white light, measuring height weekly","C) Survey gardeners about light preferences","D) Measure light intensity in a greenhouse"]','B','Compares blue vs red (with white as control), using identical plants and consistent measurements.','{"A":"No comparison to red","C":"Not an experiment","D":"Doesn''t test plant growth"}','hypothesis_evaluation','medium','Testing hypotheses requires comparing the specific conditions mentioned.'),
('a0000000-0037-0000-0000-000000000004','science','The results support which revised hypothesis?','Original hypothesis: caffeine improves all cognitive tasks. Results: caffeine improved reaction time and alertness but had no effect on creative problem-solving or memory recall.','["A) Caffeine harms cognition","B) Caffeine selectively improves speed-based tasks but not complex cognitive tasks","C) Caffeine has no effects","D) The experiment was flawed"]','B','Results show improvement in some tasks (speed) but not others (creativity, memory) = selective effect.','{"A":"It improved some tasks","C":"It improved reaction time","D":"No evidence of flaws"}','hypothesis_evaluation','hard','When results partially support a hypothesis, revise to match the specific findings.'),
-- data_trends (4 questions)
('a0000000-0038-0000-0000-000000000001','science','What trend does the data show over the 5-year period?','Global average temperature: 2019=14.8C, 2020=14.9C, 2021=14.9C, 2022=15.0C, 2023=15.1C.',NULL,'["A) Rapid decrease","B) Gradual increase","C) No change","D) Cyclical pattern"]','B','Temperature rises gradually from 14.8 to 15.1 over 5 years.','{"A":"Temperatures increasing","C":"Clear upward trend","D":"Consistent increase not cyclical"}','data_trends','easy','Look at direction of change over time: increasing, decreasing, or flat.'),
('a0000000-0038-0000-0000-000000000002','science','Based on the trend, what is the predicted value for 2024?','Sales (thousands): 2020=100, 2021=120, 2022=140, 2023=160. Linear increase of 20 per year.',NULL,'["A) 160","B) 170","C) 180","D) 200"]','C','Linear increase of 20/year: 160 + 20 = 180.','{"A":"No growth","B":"Growth of 10","D":"Growth of 40"}','data_trends','easy','For linear trends, add the constant rate of change to the last value.'),
('a0000000-0038-0000-0000-000000000003','science','At what point does the growth rate begin to slow?','Population: Year0=100, Year1=200, Year2=380, Year3=500, Year4=550, Year5=570.',NULL,'["A) Year 1","B) Year 2","C) Year 3","D) Year 4"]','C','Increases: 100, 180, 120, 50, 20. Growth rate drops significantly at Year 3.','{"A":"Still accelerating","B":"Still large increase","D":"Already slowed"}','data_trends','medium','Compare successive differences to find where increases get smaller.'),
('a0000000-0038-0000-0000-000000000004','science','Which model best fits data showing rapid initial growth that levels off?','Data: rapid increase initially, then gradual flattening toward a maximum value (S-shaped curve).',NULL,'["A) Linear model","B) Exponential growth forever","C) Logistic growth model","D) Inverse relationship"]','C','S-shaped curve with carrying capacity = logistic growth.','{"A":"Linear is straight line","B":"Exponential never levels off","D":"Inverse would decrease"}','data_trends','hard','Logistic growth: rapid at first, then slows as it approaches carrying capacity.'),

-- scientific_reasoning (4 questions)
('a0000000-0039-0000-0000-000000000001','science','Which statement is an interpretation rather than an observation?','Lab: Solution turned green at 80C. Produced 2.3mL gas. Gas likely CO2 because it extinguished a flame.',NULL,'["A) Solution turned green","B) Temperature was 80C","C) 2.3mL gas produced","D) Gas was likely CO2"]','D','Likely CO2 is an inference based on the observation of flame extinguishing.','{"A":"Directly observed","B":"Directly measured","C":"Directly measured"}','scientific_reasoning','easy','Observations = directly measured. Interpretations = reasoning about cause.'),
('a0000000-0039-0000-0000-000000000002','science','Which is the best scientific question?',NULL,NULL,'["A) Why is the sky beautiful?","B) Does increasing salt concentration affect water''s boiling point?","C) What is the best color?","D) Is chemistry hard?"]','B','Testable, specific, measurable variables, and no value judgments.','{"A":"Subjective—not testable","C":"Opinion—not measurable","D":"Subjective assessment"}','scientific_reasoning','easy','Good scientific questions are testable, measurable, and specific.'),
('a0000000-0039-0000-0000-000000000003','science','What is the most likely explanation for the unexpected result?','Expected: plant growth increases linearly with fertilizer. Observed: growth increased to 50g/L then decreased. The decrease was unexpected.','["A) Measurement error","B) Excess fertilizer may be toxic to plants","C) The experiment should be discarded","D) Plants don''t need fertilizer"]','B','Toxicity at high concentrations explains why more fertilizer eventually hurts growth.','{"A":"Consistent pattern suggests real result","C":"Unexpected results are still valid data","D":"Growth increased at lower concentrations"}','scientific_reasoning','medium','Unexpected results require explanations consistent with all the data.'),
('a0000000-0039-0000-0000-000000000004','science','Which reasoning error does this argument contain? "I took vitamin C and my cold went away in 7 days. Therefore vitamin C cured my cold."','Note: Most colds resolve in 7-10 days without treatment.',NULL,'["A) Appeal to authority","B) Confusing correlation with causation (post hoc fallacy)","C) Circular reasoning","D) Straw man argument"]','B','Cold would have resolved anyway; the vitamin C timing is coincidental not causal.','{"A":"No authority cited","C":"Not restating the conclusion as premise","D":"Not misrepresenting an argument"}','scientific_reasoning','hard','Post hoc fallacy: assuming that because B followed A, A caused B.'),

-- units_measurements (4 questions)
('a0000000-0040-0000-0000-000000000001','science','Convert 2.5 kilometers to meters.',NULL,NULL,'["A) 0.25 m","B) 25 m","C) 250 m","D) 2500 m"]','D','1 km = 1000 m. 2.5 × 1000 = 2500 m.','{"A":"Divided by 10000","B":"Divided by 100","C":"Divided by 10"}','units_measurements','easy','Kilo = 1000. Multiply km by 1000 to get meters.'),
('a0000000-0040-0000-0000-000000000002','science','A solution has pH 3. Is it acidic, neutral, or basic?',NULL,NULL,'["A) Basic","B) Neutral","C) Acidic","D) Cannot determine"]','C','pH < 7 = acidic. pH 3 is strongly acidic.','{"A":"Basic is pH > 7","B":"Neutral is pH 7","D":"pH scale directly indicates"}','units_measurements','easy','pH scale: < 7 acidic, = 7 neutral, > 7 basic.'),
('a0000000-0040-0000-0000-000000000003','science','An object travels 150 meters in 30 seconds. What is its speed in m/s?',NULL,NULL,'["A) 0.2 m/s","B) 5 m/s","C) 50 m/s","D) 4500 m/s"]','B','Speed = distance/time = 150/30 = 5 m/s.','{"A":"Inverted the fraction","C":"Multiplied by something","D":"Multiplied distance by time"}','units_measurements','medium','Speed = distance / time. Check units match.'),
('a0000000-0040-0000-0000-000000000004','science','A measurement is reported as 3.42 +/- 0.05 g. What does the +/- value represent?',NULL,NULL,'["A) The mass of the container","B) The uncertainty or margin of error in the measurement","C) A second measurement","D) The temperature correction"]','B','The +/- value indicates measurement uncertainty or precision.','{"A":"Not related to container","C":"Not a separate measurement","D":"Not temperature related"}','units_measurements','medium','Plus-minus (±) values indicate measurement uncertainty or error margins.');
